			THEN TRUE
			ELSE
			((
				st_distance_sphere(
					st_makepoint(NEW.lon,NEW.lat),--new lon/lat
					st_makepoint((SELECT lon FROM prev_d),(SELECT lat FROM prev_d))--prev
				)
