-- VIEW: ttn

--DROP VIEW ttn;

CREATE OR REPLACE VIEW ttn AS
	SELECT
		sh.id AS nomer,
		sh.ship_date_time::date AS data,
		
		coalesce(cl.name||' ', '')||
		coalesce('ИНН '||cl.inn||' ', '')||
		coalesce('КПП '||cl.kpp||' ', '')||
		coalesce(', '||cl.address_legal, '')		
		AS platelschik,
		 
		sh.quant AS nomen_kol,
		ct.name AS nomen_naim,
		'0.00' AS nomen_cena,
		'0.00' AS nomen_summa
		
	FROM shipments AS sh
	LEFT JOIN orders o ON o.id = sh.order_id
	LEFT JOIN clients cl ON cl.id = o.client_id
	LEFT JOIN concrete_types ct ON ct.id = o.concrete_type_id
	;
	
ALTER VIEW ttn OWNER TO beton;


