CREATE OR REPLACE FUNCTION banks.banks_upsert(
	in_bik varchar(9),
	in_codegr varchar(9),
	in_name varchar(50),
	in_korshet varchar(20),
	in_adres varchar(70),
	in_gor varchar(31),
	in_tgroup bool
)
  RETURNS void AS
$$
	INSERT INTO banks.banks
	(bik,codegr,name,korshet,adres,gor,tgroup)
	VALUES (in_bik,in_codegr,in_name,in_korshet,in_adres,in_gor,in_tgroup)
	ON CONFLICT (bik) DO UPDATE SET
		codegr = in_codegr,
		name = in_name,
		korshet = in_korshet,
		adres = in_adres,
		gor = in_gor,
		tgroup = in_tgroup
	;
$$
  LANGUAGE sql VOLATILE
  CALLED ON NULL INPUT
  COST 100;
