-- View: raw_material_cons_rates_dates_list

-- DROP VIEW raw_material_cons_rates_dates_list;

CREATE OR REPLACE VIEW raw_material_cons_rates_dates_list AS 
	SELECT
		d_from.id,
		d_from.dt,
		date8_descr(d_from.dt) AS dt_descr,
		/*(date8_descr(d_from.dt)::text || ' - '::text) || COALESCE(
			( SELECT date8_descr((d_to.dt - '1 day'::interval)::date)::text AS date
			FROM raw_material_cons_rate_dates d_to
			WHERE d_to.dt > d_from.dt
			ORDER BY d_to.dt
			LIMIT 1
			),
			CASE
				WHEN now()::date < d_from.dt THEN '---'::text
				ELSE date8_descr(now()::date)::text
			END
		) AS period,*/
		
		to_char(d_from.dt,'DD/MM/YY HH24:MI') || ' - '::text ||
		COALESCE(
			( SELECT
			 	to_char(d_to.dt-'1 second'::interval, 'DD/MM/YY HH24:MI') AS date
			FROM raw_material_cons_rate_dates d_to
			WHERE d_to.dt > d_from.dt
			ORDER BY d_to.dt
			LIMIT 1
			),
			CASE
				WHEN now() < d_from.dt THEN '---'::text
				ELSE to_char(now(),'DD/MM/YY HH24:MI')
			END
		) AS period,
		
		d_from.name,
		d_from.code
		
	FROM raw_material_cons_rate_dates d_from
	ORDER BY d_from.dt DESC;

ALTER TABLE raw_material_cons_rates_dates_list
  OWNER TO beton;



-- ******************* update 19/11/2021 08:55:14 ******************
-- FUNCTION: public.raw_material_cons_rates(integer, timestamp without time zone)

-- DROP FUNCTION public.raw_material_cons_rates(integer, timestamp without time zone);

CREATE OR REPLACE FUNCTION public.raw_material_cons_rates(
	in_concrete_type_id integer,
	in_date_time timestamp without time zone)
    RETURNS TABLE(concrete_type_id integer, material_id integer, rate numeric) 
    LANGUAGE 'sql'

    COST 100
    VOLATILE 
    ROWS 1000
AS $BODY$
	SELECT
		rates.concrete_type_id,
		rates.raw_material_id AS material_id,
		rates.rate
	FROM raw_material_cons_rates AS rates
	WHERE 
		rates.rate_date_id=(
			SELECT id
			FROM raw_material_cons_rate_dates
			WHERE dt <= $2
			ORDER BY dt DESC
			LIMIT 1
			)
		AND (
			($1 IS NULL OR $1=0)
			OR ($1>0 AND rates.concrete_type_id = $1)
		)
	;
$BODY$;

ALTER FUNCTION public.raw_material_cons_rates(integer, timestamp without time zone)
    OWNER TO beton;

GRANT EXECUTE ON FUNCTION public.raw_material_cons_rates(integer, timestamp without time zone) TO beton;

GRANT EXECUTE ON FUNCTION public.raw_material_cons_rates(integer, timestamp without time zone) TO PUBLIC;




