﻿-- Function: demurrage_cost_per_hour_on_date(in_date_time timestamp)

-- DROP FUNCTION demurrage_cost_per_hour_on_date(in_date_time timestamp);

CREATE OR REPLACE FUNCTION demurrage_cost_per_hour_on_date(in_date_time timestamp)
  RETURNS numeric(15,2) AS
$$
	SELECT val::numeric(15,2)
	FROM period_values
	WHERE period_value_type = 'demurrage_cost_per_hour' AND key=0
		AND date_time <= in_date_time
	ORDER BY date_time desc
	LIMIT 1;
$$
  LANGUAGE sql VOLATILE
  COST 100;
ALTER FUNCTION demurrage_cost_per_hour_on_date(in_date_time timestamp) OWNER TO beton;


