-- ******************* update 09/02/2022 08:32:04 ******************
-- Function: public.doc_material_procurements_process()

-- DROP FUNCTION public.doc_material_procurements_process();

CREATE OR REPLACE FUNCTION public.doc_material_procurements_process()
  RETURNS trigger AS
$BODY$
DECLARE
	reg_act ra_materials%ROWTYPE;
	reg_material_facts ra_material_facts%ROWTYPE;
	reg_cement ra_cement%ROWTYPE;
	v_dif_store bool;
	v_production_site_id int;
BEGIN
	IF (TG_WHEN='BEFORE' AND TG_OP='INSERT') THEN
		-- Временно!
		NEW.production_base_id = 1;
		
		RETURN NEW;
		
	ELSIF (TG_WHEN='AFTER') AND (TG_OP='INSERT' OR TG_OP='UPDATE') THEN					
		IF (TG_OP='INSERT') THEN						
			--log
			PERFORM doc_log_insert('material_procurement'::doc_types,NEW.id,NEW.date_time);
		END IF;

		--register actions ra_materials
		reg_act.date_time		= NEW.date_time;
		reg_act.deb			= true;
		reg_act.doc_type  		= 'material_procurement'::doc_types;
		reg_act.doc_id  		= NEW.id;
		reg_act.production_base_id	= NEW.production_base_id;
		reg_act.material_id		= NEW.material_id;
		reg_act.quant			= NEW.quant_net;
		PERFORM ra_materials_add_act(reg_act);	
		
		SELECT dif_store INTO v_dif_store FROM raw_materials WHERE id=NEW.material_id;
		--По материалам делаем всегда движения, а если есть учет по силосам и есть силос - то и по силосам
		--Если учет по заводам (v_dif_store==TRUE)- то по заводам
		--register actions ra_material_facts
		reg_material_facts.date_time		= NEW.date_time;
		reg_material_facts.deb			= true;
		reg_material_facts.doc_type  		= 'material_procurement'::doc_types;
		reg_material_facts.doc_id  		= NEW.id;
		reg_material_facts.material_id		= NEW.material_id;
		IF coalesce(v_dif_store,FALSE) AND coalesce(NEW.store,'')<>'' THEN
			--Определить завод по приходу
			SELECT production_site_id INTO v_production_site_id FROM store_map_to_production_sites WHERE store = NEW.store;
			--RAISE EXCEPTION 'v_production_site_id=%',v_production_site_id;
			IF v_production_site_id IS NULL THEN
				-- no match!
				INSERT INTO store_map_to_production_sites (store) VALUES (NEW.store);
			END IF;
			reg_material_facts.production_site_id = v_production_site_id;
		END IF;
		reg_material_facts.quant		= NEW.quant_net;
		PERFORM ra_material_facts_add_act(reg_material_facts);	
		
		IF coalesce( (SELECT is_cement FROM raw_materials WHERE id = NEW.material_id),FALSE)
		AND NEW.cement_silos_id IS NOT NULL THEN
			--register actions ra_cement
			reg_cement.date_time		= NEW.date_time;
			reg_cement.deb			= true;
			reg_cement.doc_type  		= 'material_procurement'::doc_types;
			reg_cement.doc_id  		= NEW.id;
			reg_cement.cement_silos_id	= NEW.cement_silos_id;
			reg_cement.quant		= NEW.quant_net;
			PERFORM ra_cement_add_act(reg_cement);	
			
		END IF;
			
		--Event support
		PERFORM pg_notify(
				'RAMaterialFact.change'
			,json_build_object(
				'params',json_build_object(
					'cond_date',NEW.date_time::date
				)
			)::text
		);
				
		RETURN NEW;
		
	ELSIF (TG_WHEN='BEFORE' AND TG_OP='UPDATE') THEN
		PERFORM ra_materials_remove_acts('material_procurement'::doc_types,OLD.id);
		PERFORM ra_material_facts_remove_acts('material_procurement'::doc_types,OLD.id);
		PERFORM ra_cement_remove_acts('material_procurement'::doc_types,OLD.id);

		IF NEW.date_time<>OLD.date_time THEN
			PERFORM doc_log_update('material_procurement'::doc_types,NEW.id,NEW.date_time);
		END IF;
						
		RETURN NEW;
	ELSIF (TG_WHEN='AFTER' AND TG_OP='DELETE') THEN
	
		--Event support
		PERFORM pg_notify(
				'RAMaterialFact.change'
			,json_build_object(
				'params',json_build_object(
					'cond_date',OLD.date_time::date
				)
			)::text
		);
	
		RETURN OLD;
	ELSIF (TG_WHEN='BEFORE' AND TG_OP='DELETE') THEN
		--detail tables
		
		--register actions										
		PERFORM ra_materials_remove_acts('material_procurement'::doc_types,OLD.id);
		PERFORM ra_material_facts_remove_acts('material_procurement'::doc_types,OLD.id);
		PERFORM ra_cement_remove_acts('material_procurement'::doc_types,OLD.id);
		
		--log
		PERFORM doc_log_delete('material_procurement'::doc_types,OLD.id);
		
		RETURN OLD;
	END IF;
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION public.doc_material_procurements_process()
  OWNER TO beton;



-- ******************* update 09/02/2022 08:51:14 ******************
-- FUNCTION: public.rg_materials_update_periods(timestamp without time zone, integer, numeric)

-- DROP FUNCTION public.rg_materials_update_periods(timestamp without time zone, integer, numeric);

CREATE OR REPLACE FUNCTION public.rg_materials_update_periods(
	in_date_time timestamp without time zone,
	in_production_base_id integer,
	in_material_id integer,
	in_delta_quant numeric)
    RETURNS void
    LANGUAGE 'plpgsql'

    COST 100
    VOLATILE 
AS $BODY$
DECLARE
	v_loop_rg_period timestamp;
	v_calc_interval interval;			  			
	CURRENT_BALANCE_DATE_TIME timestamp;
	CALC_DATE_TIME timestamp;
BEGIN
	CALC_DATE_TIME = rg_calc_period('material'::reg_types);
	v_loop_rg_period = rg_period('material'::reg_types,in_date_time);
	v_calc_interval = rg_calc_interval('material'::reg_types);
	LOOP
		UPDATE rg_materials
		SET
			quant = quant + in_delta_quant
		WHERE 
			date_time=v_loop_rg_period
			AND production_base_id = in_production_base_id
			AND material_id = in_material_id;
			
		IF NOT FOUND THEN
			BEGIN
				INSERT INTO rg_materials (date_time
				,production_base_id
				,material_id
				,quant)				
				VALUES (v_loop_rg_period
				,in_production_base_id
				,in_material_id
				,in_delta_quant);
			EXCEPTION WHEN OTHERS THEN
				UPDATE rg_materials
				SET
					quant = quant + in_delta_quant
				WHERE date_time = v_loop_rg_period
				AND production_base_id = in_production_base_id
				AND material_id = in_material_id;
			END;
		END IF;
		v_loop_rg_period = v_loop_rg_period + v_calc_interval;
		IF v_loop_rg_period > CALC_DATE_TIME THEN
			EXIT;  -- exit loop
		END IF;
	END LOOP;
	
	--Current balance
	CURRENT_BALANCE_DATE_TIME = reg_current_balance_time();
	UPDATE rg_materials
	SET
		quant = quant + in_delta_quant
	WHERE 
		date_time=CURRENT_BALANCE_DATE_TIME
		AND production_base_id = in_production_base_id
		AND material_id = in_material_id;
		
	IF NOT FOUND THEN
		BEGIN
			INSERT INTO rg_materials (date_time
			,production_base_id
			,material_id
			,quant)				
			VALUES (CURRENT_BALANCE_DATE_TIME
			,in_production_base_id
			,in_material_id
			,in_delta_quant);
		EXCEPTION WHEN OTHERS THEN
			UPDATE rg_materials
			SET
				quant = quant + in_delta_quant
			WHERE 
				date_time=CURRENT_BALANCE_DATE_TIME
				AND production_base_id = in_production_base_id
				AND material_id = in_material_id;
		END;
	END IF;					
	
END;
$BODY$;

ALTER FUNCTION public.rg_materials_update_periods(timestamp without time zone, integer, numeric)
    OWNER TO beton;



-- ******************* update 09/02/2022 08:55:40 ******************
-- FUNCTION: public.rg_material_set_custom_period(timestamp without time zone)

-- DROP FUNCTION public.rg_material_set_custom_period(timestamp without time zone);

CREATE OR REPLACE FUNCTION public.rg_material_set_custom_period(
	in_new_period timestamp without time zone)
    RETURNS void
    LANGUAGE 'plpgsql'

    COST 100
    VOLATILE 
AS $BODY$
DECLARE
	NEW_PERIOD timestamp without time zone;
	v_prev_current_period timestamp without time zone;
	v_current_period timestamp without time zone;
	CURRENT_PERIOD timestamp without time zone;
	TA_PERIOD timestamp without time zone;
	REG_INTERVAL interval;
BEGIN
	NEW_PERIOD = rg_calc_period_start('material'::reg_types, in_new_period);
	SELECT date_time INTO CURRENT_PERIOD FROM rg_calc_periods WHERE reg_type = 'material'::reg_types;
	TA_PERIOD = reg_current_balance_time();
	--iterate through all periods between CURRENT_PERIOD and NEW_PERIOD
	REG_INTERVAL = rg_calc_interval('material'::reg_types);
	v_prev_current_period = CURRENT_PERIOD;		
	LOOP
		v_current_period = v_prev_current_period + REG_INTERVAL;
		IF v_current_period > NEW_PERIOD THEN
			EXIT;  -- exit loop
		END IF;
		--clear period
		DELETE FROM rg_materials
		WHERE date_time = v_current_period;
		--new data
		INSERT INTO rg_materials
		(date_time
		,production_base_id
		,material_id
		,quant						
		)
		(SELECT
				v_current_period
				,rg.production_base_id
				,rg.material_id
				,rg.quant				
			FROM rg_materials As rg
			WHERE (
			rg.quant<>0
			)
			AND (rg.date_time=v_prev_current_period)
		);
		v_prev_current_period = v_current_period;
	END LOOP;
	--new TA data
	DELETE FROM rg_materials
	WHERE date_time=TA_PERIOD;
--RAISE EXCEPTION 'FromPeriod=%',NEW_PERIOD-REG_INTERVAL;	
	INSERT INTO rg_materials
	(date_time
	,production_base_id
	,material_id
	,quant	
	)
	(SELECT
		TA_PERIOD
		,rg.production_base_id
		,rg.material_id
		,rg.quant
		FROM rg_materials AS rg
		WHERE (
		rg.quant<>0
		)
		AND (rg.date_time=NEW_PERIOD-REG_INTERVAL)
	);
	DELETE FROM rg_materials WHERE (date_time>NEW_PERIOD)
	AND (date_time<>TA_PERIOD);
	--set new period
	UPDATE rg_calc_periods SET date_time = NEW_PERIOD
	WHERE reg_type='material'::reg_types;		
END
$BODY$;

ALTER FUNCTION public.rg_material_set_custom_period(timestamp without time zone)
    OWNER TO beton;



-- ******************* update 09/02/2022 08:56:37 ******************
-- FUNCTION: public.ra_materials_process()

-- DROP FUNCTION public.ra_materials_process();

CREATE OR REPLACE FUNCTION public.ra_materials_process()
    RETURNS trigger
    LANGUAGE 'plpgsql'
    COST 100
    VOLATILE NOT LEAKPROOF
AS $BODY$
DECLARE
		v_delta_quant  numeric(19,3) DEFAULT 0;
		
		CALC_DATE_TIME timestamp without time zone;
		CURRENT_BALANCE_DATE_TIME timestamp without time zone;
		v_loop_rg_period timestamp without time zone;
		v_calc_interval interval;			  			
	BEGIN
		IF (TG_WHEN='BEFORE' AND TG_OP='INSERT') THEN
			RETURN NEW;
		ELSIF (TG_WHEN='BEFORE' AND TG_OP='UPDATE') THEN
			RETURN NEW;
		ELSIF (TG_WHEN='AFTER' AND (TG_OP='UPDATE' OR TG_OP='INSERT')) THEN
			CALC_DATE_TIME = rg_calc_period('material'::reg_types);
			IF (CALC_DATE_TIME IS NULL) OR (NEW.date_time::date > rg_period_balance('material'::reg_types, CALC_DATE_TIME)) THEN
				CALC_DATE_TIME = rg_period('material'::reg_types,NEW.date_time);
				PERFORM rg_material_set_custom_period(CALC_DATE_TIME);						
			END IF;

			IF TG_OP='UPDATE' AND
			(NEW.date_time<>OLD.date_time
			OR NEW.production_base_id<>OLD.production_base_id
			OR NEW.material_id<>OLD.material_id
			) THEN
				--delete old data completely
				PERFORM rg_materials_update_periods(OLD.date_time, OLD.production_base_id, OLD.material_id, -1*OLD.quant);
				v_delta_quant = 0;
			ELSIF TG_OP='UPDATE' THEN						
				v_delta_quant = OLD.quant;
			ELSE
				v_delta_quant = 0;
			END IF;
			
			v_delta_quant = NEW.quant - v_delta_quant;
			IF NOT NEW.deb THEN
				v_delta_quant = -1 * v_delta_quant;
			END IF;

			PERFORM rg_materials_update_periods(NEW.date_time, NEW.production_base_id, NEW.material_id, v_delta_quant);
		
			RETURN NEW;					
		ELSIF (TG_WHEN='BEFORE' AND TG_OP='DELETE') THEN
			RETURN OLD;
		ELSIF (TG_WHEN='AFTER' AND TG_OP='DELETE') THEN
			CALC_DATE_TIME = rg_calc_period('material'::reg_types);
			IF (CALC_DATE_TIME IS NULL) OR (OLD.date_time::date > rg_period_balance('material'::reg_types, CALC_DATE_TIME)) THEN
				CALC_DATE_TIME = rg_period('material'::reg_types,OLD.date_time);
				PERFORM rg_material_set_custom_period(CALC_DATE_TIME);						
			END IF;
			v_delta_quant = OLD.quant;
			IF OLD.deb THEN
				v_delta_quant = -1*v_delta_quant;					
			END IF;

			PERFORM rg_materials_update_periods(OLD.date_time, OLD.production_base_id, OLD.material_id, v_delta_quant);
		
			RETURN OLD;					
		END IF;
	END;
$BODY$;

ALTER FUNCTION public.ra_materials_process()
    OWNER TO beton;



-- ******************* update 09/02/2022 09:04:50 ******************
-- Function: public.set_vehicle_busy()

-- DROP FUNCTION public.set_vehicle_busy();

CREATE OR REPLACE FUNCTION public.set_vehicle_busy()
  RETURNS trigger AS
$BODY$
DECLARE
	dest_id int;
	new_state vehicle_states;
	v_feature vehicles.feature%TYPE;
	reg_act ra_material_consumption%ROWTYPE;
	reg_act_mat ra_materials%ROWTYPE;
	v_concrete_type_id int;
	v_vehicle_id int;
	v_driver_id int;
	rate_row RECORD;
	v_avg_dev numeric;
	v_production_base_id int;
BEGIN
	--change state only if 1) insert
	--		       2) update && shipped false==>true
	IF (TG_OP='INSERT') OR (TG_OP='UPDATE' AND OLD.shipped=false AND NEW.shipped) THEN
		IF NEW.shipped THEN
			new_state = 'busy'::vehicle_states;
			
			--if self-shipment && empty feature - set state out
			SELECT o.destination_id INTO dest_id FROM orders AS o WHERE o.id=NEW.order_id;
			IF dest_id = constant_self_ship_dest_id() THEN
				SELECT v.feature INTO v_feature FROM vehicle_schedules AS vs
				LEFT JOIN vehicles AS v ON v.id=vs.vehicle_id
				WHERE vs.id=NEW.vehicle_schedule_id;
				
				IF (v_feature IS NULL) OR (v_feature='') THEN
					new_state = 'out'::vehicle_states;
				END IF;
			END IF;
		END IF;
		
		INSERT INTO vehicle_schedule_states
		(date_time,state,shipment_id,schedule_id,tracker_id,destination_id)
		VALUES(current_timestamp,
		CASE
		WHEN NEW.shipped THEN
			new_state
		ELSE
			'assigned'::vehicle_states
		END,
		NEW.id,NEW.vehicle_schedule_id,
		get_vehicle_tracker_id_on_schedule_id(NEW.vehicle_schedule_id),dest_id);

	END IF;

	IF (TG_OP='INSERT') THEN
		--log
		PERFORM doc_log_insert('shipment'::doc_types,NEW.id,NEW.date_time);
	ELSE
		--IF NEW.ship_date_time<>OLD.ship_date_time THEN
			PERFORM doc_log_update('shipment'::doc_types,NEW.id,NEW.ship_date_time);
		--END IF;			
	END IF;

	IF (TG_OP='INSERT' OR TG_OP='UPDATE') AND (NEW.shipped) THEN	
		SELECT o.concrete_type_id INTO v_concrete_type_id FROM orders AS o WHERE o.id=NEW.order_id;
		SELECT sch.vehicle_id,sch.driver_id INTO v_vehicle_id,v_driver_id FROM vehicle_schedules As sch WHERE sch.id=NEW.vehicle_schedule_id;
		
		--concrete
		--reg acts				
		reg_act.date_time		= NEW.ship_date_time;
		reg_act.doc_type  		= 'shipment'::doc_types;
		reg_act.doc_id  		= NEW.id;
		reg_act.concrete_type_id 	= v_concrete_type_id;
		reg_act.vehicle_id 		= v_vehicle_id;
		reg_act.driver_id 		= v_driver_id;
		reg_act.concrete_quant		= NEW.quant;
		reg_act.material_quant		= 0;
		reg_act.material_quant_norm	= 0;
		PERFORM ra_material_consumption_add_act(reg_act);	


		SELECT production_base_id INTO v_production_base_id
		FROM production_sites
		WHERE id = NEW.production_site_id;
		
		--materials		
		FOR rate_row IN
			SELECT * FROM raw_material_cons_rates(v_concrete_type_id,NEW.ship_date_time)
		LOOP
			v_avg_dev = 0;--raw_mat_cons_avg_dev(NEW.ship_date_time::date,rate_row.material_id)*NEW.quant;
			
			--reg acts				
			reg_act.date_time		= NEW.ship_date_time;
			reg_act.doc_type  		= 'shipment'::doc_types;
			reg_act.doc_id  		= NEW.id;
			reg_act.concrete_type_id 	= v_concrete_type_id;
			reg_act.vehicle_id 		= v_vehicle_id;
			reg_act.driver_id 		= v_driver_id;			
			reg_act.material_id 		= rate_row.material_id;
			reg_act.material_quant		= (rate_row.rate*NEW.quant) + v_avg_dev;
			reg_act.material_quant_norm	= rate_row.rate*NEW.quant;
			reg_act.material_quant_corrected= (rate_row.rate*NEW.quant) + v_avg_dev;
			reg_act.concrete_quant		= 0;
			PERFORM ra_material_consumption_add_act(reg_act);	

			--reg materials
			reg_act_mat.date_time		= NEW.ship_date_time;
			reg_act_mat.deb			= false;
			reg_act_mat.doc_type  		= 'shipment'::doc_types;
			reg_act_mat.doc_id  		= NEW.id;
			reg_act_mat.production_base_id	= v_production_base_id;
			reg_act_mat.material_id		= rate_row.material_id;
			reg_act_mat.quant		= rate_row.rate*NEW.quant;
			PERFORM ra_materials_add_act(reg_act_mat);	
			
		END LOOP;
		
		--пересчет нарушения норма/факт по производству
		UPDATE productions
		SET
			material_tolerance_violated = productions_get_mat_tolerance_violated(
				production_site_id,
				production_id
			)
		WHERE shipment_id = NEW.id;
	END IF;
	
	RETURN NEW;
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION public.set_vehicle_busy()
  OWNER TO beton;



-- ******************* update 09/02/2022 10:38:49 ******************
-- FUNCTION: public.rg_materials_balance(integer[],integer[])

-- DROP FUNCTION public.rg_materials_balance(integer[],integer[]);

CREATE OR REPLACE FUNCTION public.rg_materials_balance(
	in_production_base_id_ar integer[]
	,in_material_id_ar integer[])
    RETURNS TABLE(production_base_id int, material_id integer, quant numeric) 
    LANGUAGE 'plpgsql'

    COST 100
    VOLATILE STRICT 
    ROWS 1000
AS $BODY$
BEGIN
	RETURN QUERY 
	SELECT
		b.production_base_id
		,b.material_id
		,b.quant AS quant				
	FROM rg_materials AS b
	WHERE b.date_time=reg_current_balance_time()
		
		AND (ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (b.production_base_id_ar=ANY(in_production_base_id_ar)))
		AND (ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (b.material_id=ANY(in_material_id_ar)))
		
		AND(
		b.quant<>0
		)
	ORDER BY
		b.production_base_id
		,b.material_id;
END;
$BODY$;

ALTER FUNCTION public.rg_materials_balance(integer[],integer[])
    OWNER TO beton;



-- ******************* update 09/02/2022 10:43:18 ******************
-- FUNCTION: public.rg_materials_balance(doc_types, integer, integer[])

-- DROP FUNCTION public.rg_materials_balance(doc_types, integer, integer[], integer[]);

CREATE OR REPLACE FUNCTION public.rg_materials_balance(
	in_doc_type doc_types,
	in_doc_id integer,
	in_production_base_id_ar integer[],
	in_material_id_ar integer[]
	)
    RETURNS TABLE(
    	production_base_id integer
    	,material_id integer
    	, quant numeric
    ) 
    LANGUAGE 'plpgsql'

    COST 100
    VOLATILE STRICT 
    ROWS 1000
AS $BODY$
DECLARE
	v_doc_date_time timestamp without time zone;
	v_doc_id int;
	v_cur_per timestamp;
	v_act_direct boolean;
	v_act_direct_sgn int;
	v_calc_interval interval;
BEGIN
	SELECT id,date_time INTO v_doc_id,v_doc_date_time FROM doc_log WHERE doc_type=in_doc_type AND doc_id=in_doc_id;
	v_cur_per = rg_period('material'::reg_types, v_doc_date_time);
	v_calc_interval = rg_calc_interval('material'::reg_types);
	v_act_direct = ( (rg_calc_period_end('material'::reg_types,v_cur_per)-v_doc_date_time)>(v_doc_date_time - v_cur_per) );
	IF v_act_direct THEN
		v_act_direct_sgn = 1;
	ELSE
		v_act_direct_sgn = -1;
	END IF;

	RETURN QUERY 
	SELECT 
	sub.production_base_id
	,sub.material_id
	,SUM(sub.quant) AS quant				
	FROM(
	SELECT
	
	b.production_base_id
	,b.material_id
	,b.quant				
	FROM rg_materials AS b
	WHERE (v_act_direct AND b.date_time = (v_cur_per-v_calc_interval)) OR (NOT v_act_direct AND b.date_time = v_cur_per)
	
	AND (ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (b.production_base_id=ANY(in_production_base_id_ar)))
	AND (ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (b.material_id=ANY(in_material_id_ar)))
	
	AND(
	b.quant<>0
	)
	
	UNION ALL
	
	(SELECT
	
	act.production_base_id
	,act.material_id
	,
	CASE act.deb
		WHEN TRUE THEN act.quant*v_act_direct_sgn
		ELSE -act.quant*v_act_direct_sgn
	END AS quant								
	FROM doc_log
	LEFT JOIN ra_materials AS act ON act.doc_type=doc_log.doc_type AND act.doc_id=doc_log.doc_id
	WHERE (v_act_direct AND (doc_log.date_time>=v_cur_per AND doc_log.id<v_doc_id) )
		OR (NOT v_act_direct AND (doc_log.date_time<(v_cur_per+v_calc_interval) AND doc_log.id>=v_doc_id) )				
	
	AND (ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (act.production_base_id=ANY(in_production_base_id_ar)))
	AND (ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (act.material_id=ANY(in_material_id_ar)))
	
	AND (
	
	act.quant<>0
	)
	ORDER BY doc_log.date_time,doc_log.id)
	) AS sub
	WHERE (
		ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (sub.production_base_id=ANY(in_production_base_id_ar))
		AND ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (sub.material_id=ANY(in_material_id_ar))
	)
	GROUP BY
	
	sub.production_base_id
	,sub.material_id
	HAVING
	
	SUM(sub.quant)<>0
					
	ORDER BY
	sub.production_base_id
	,sub.material_id
	;
END;
$BODY$;

ALTER FUNCTION public.rg_materials_balance(doc_types, integer, integer[], integer[])
    OWNER TO beton;



-- ******************* update 09/02/2022 10:46:56 ******************
-- FUNCTION: public.rg_materials_balance(timestamp without time zone, integer[])

-- DROP FUNCTION public.rg_materials_balance(timestamp without time zone, integer[], integer[]);

CREATE OR REPLACE FUNCTION public.rg_materials_balance(
	in_date_time timestamp without time zone,
	in_production_base_id_ar integer[],
	in_material_id_ar integer[])
    RETURNS TABLE(
    	production_base_id integer
    	,material_id integer,
    	quant numeric) 
    LANGUAGE 'plpgsql'

    COST 100
    VOLATILE STRICT 
    ROWS 1000
AS $BODY$
DECLARE
	v_cur_per timestamp;
	v_act_direct boolean;
	v_act_direct_sgn int;
	v_calc_interval interval;
BEGIN
	v_cur_per = rg_period('material'::reg_types, in_date_time);
	v_calc_interval = rg_calc_interval('material'::reg_types);
	v_act_direct = TRUE;--( (rg_calc_period_end('material'::reg_types,v_cur_per)-in_date_time)>(in_date_time - v_cur_per) );
	v_act_direct_sgn = 1;
	/*
	IF v_act_direct THEN
		v_act_direct_sgn = 1;
	ELSE
		v_act_direct_sgn = -1;
	END IF;
	*/
	--RAISE 'v_act_direct=%, v_cur_per=%, v_calc_interval=%',v_act_direct,v_cur_per,v_calc_interval;
	RETURN QUERY 
	SELECT 
	
	sub.production_base_id
	,sub.material_id
	,SUM(sub.quant) AS quant				
	FROM(
		SELECT
		
		b.production_base_id
		,b.material_id
		,b.quant				
		FROM rg_materials AS b
		WHERE (v_act_direct AND b.date_time = (v_cur_per-v_calc_interval)) OR (NOT v_act_direct AND b.date_time = v_cur_per)
		
		AND (ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (b.production_base_id=ANY(in_production_base_id_ar)))
		AND (ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (b.material_id=ANY(in_material_id_ar)))
		
		AND (
		b.quant<>0
		)
		
		UNION ALL
		
		(SELECT
		
		act.production_base_id
		,act.material_id
		,CASE act.deb
			WHEN TRUE THEN act.quant*v_act_direct_sgn
			ELSE -act.quant*v_act_direct_sgn
		END AS quant
										
		FROM doc_log
		LEFT JOIN ra_materials AS act ON act.doc_type=doc_log.doc_type AND act.doc_id=doc_log.doc_id
		WHERE (v_act_direct AND (doc_log.date_time>=v_cur_per AND doc_log.date_time<in_date_time) )
			OR (NOT v_act_direct AND (doc_log.date_time<(v_cur_per+v_calc_interval) AND doc_log.date_time>=in_date_time) )
		
		AND (ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (act.production_base_id=ANY(in_production_base_id_ar)))
		AND (ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (act.material_id=ANY(in_material_id_ar)))
		
		AND (
		
		act.quant<>0
		)
		ORDER BY doc_log.date_time,doc_log.id)

		UNION ALL
		--РУЧНЫЕ ИЗМЕНЕНИЯ
		(SELECT
		act.production_base_id
		,act.material_id
		,CASE act.deb
			WHEN TRUE THEN act.quant
			ELSE -act.quant
		END AS quant
										
		FROM ra_materials AS act
		
		WHERE (v_act_direct AND (act.date_time>=v_cur_per AND act.date_time<in_date_time)
			OR (NOT v_act_direct AND (act.date_time<(v_cur_per+v_calc_interval) AND act.date_time>=in_date_time) )
			)
		
		AND (ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (act.production_base_id=ANY(in_production_base_id_ar)))
		AND (ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (act.material_id=ANY(in_material_id_ar)))
		AND act.doc_type IS NULL AND act.doc_id IS NULL
		AND (
		
		act.quant<>0
		)
		)
		
	) AS sub
	WHERE
		(ARRAY_LENGTH(in_production_base_id_ar,1) IS NULL OR (sub.production_base_id=ANY(in_production_base_id_ar)))
		AND (ARRAY_LENGTH(in_material_id_ar,1) IS NULL OR (sub.material_id=ANY(in_material_id_ar)))
	
	GROUP BY
		sub.production_base_id
		,sub.material_id
	HAVING
		
		SUM(sub.quant)<>0
						
	ORDER BY
		sub.production_base_id,
		sub.material_id;
END;
