﻿-- Function: notifications.add_notification(in_params jsonb)

-- DROP FUNCTION notifications.add_notification(in_params jsonb);

/**
 * app_id int
 * messages {
 * 	ext_obj json
 * 	tm {
 *		структура телеграм
 * 	}
 * 	sms {
 *		структура СМС
 * 	}
 * 	email {
 *
 * 	}
 * }
 *
 * Отправляет события для оповещения workers
 */
CREATE OR REPLACE FUNCTION notifications.add_notification(in_params jsonb)
  RETURNS void AS
$$
DECLARE
	v_sent bool;
	v_mail_id int;
	v_tm_id int;
	v_sms_id int;
	msg json;
	v_tm_note bool;
	v_sms_note bool;
	v_email_note bool;
	v_tm jsonb;
BEGIN
	FOR msg IN SELECT * FROM jsonb_array_elements(in_params->'messages')
	LOOP
		v_sent = FALSE;
		IF msg->'tm' IS NOT NULL THEN
			SELECT
				(msg->'tm')::jsonb || jsonb_build_object('chat_id', tm_user->>'id')
			INTO
				v_tm
			FROM notifications.ext_users
			WHERE app_id = (in_params->>'app_id')::int
				AND ext_obj->>'dataType' = msg->'ext_obj'->>'dataType'
				AND (ext_obj->'keys'->>'id')::int = (msg->'ext_obj'->'keys'->>'id')::int;
				
			
			IF v_tm IS NOT NULL AND v_tm->'chat_id' IS NOT NULL THEN
				-- telegram user exists
				INSERT INTO notifications.tm_out_messages (app_id, message)
				VALUES ((in_params->>'app_id')::int, v_tm)
				RETURNING id INTO v_tm_id;
				v_sent = TRUE;
				
				v_tm_note = TRUE;
			END IF;
		END IF;


		IF coalesce(v_sent,FALSE) = FALSE AND msg->'sms' IS NOT NULL THEN
			v_sent = TRUE;
			INSERT INTO notifications.sms (app_id, tel, body, sms_type, doc_ref)
			VALUES (
				 (in_params->>'app_id')::int,
				 msg->'sms'->>'tel',
				 msg->'sms'->>'body',
				 msg->'sms'->>'sms_type',
				 msg->'sms'->'doc_ref'
			)
			RETURNING id INTO v_sms_id;
			v_sms_note = TRUE;
		END IF;
		
		IF coalesce(v_sent,FALSE) = FALSE AND msg->'email' IS NOT NULL THEN
			INSERT INTO notifications.mail_messages (app_id, from_addr, from_name, to_addr, to_name, reply_addr, reply_name,
				body, sender_addr, subject, email_type)
			VALUES (
				 (in_params->>'app_id')::int,
				 msg->'email'->>'from_addr',
				 msg->'email'->>'from_name',
				 msg->'email'->>'to_addr',
				 msg->'email'->>'to_name',
				 msg->'email'->>'reply_addr',
				 msg->'email'->>'reply_name',
				 msg->'email'->>'body',
				 msg->'email'->>'sender_addr',
				 msg->'email'->>'subject',
				 msg->'email'->>'email_type'
			)
			RETURNING id INTO v_mail_id;
			
			IF msg->'email'->'attachments' IS NOT NULL THEN
				INSERT INTO notifications.mail_message_attachments (mail_message_id, file_name)	
				SELECT
					v_mail_id,
					att->>'file_name'				
				FROM jsonb_array_elements((msg->'email'->'attachments')::jsonb) AS att;
			END IF;
			
			v_email_note = TRUE;
		END IF;	
	END LOOP;
	/*
	IF v_tm_note THEN
		PERFORM pg_notify('Notification.tm',
			jsonb_build_object(
				'id', v_tm_id::text,
				'app_id', in_params->>'app_id'
			)::text
		);
	END IF;
	
	IF v_sms_note THEN
		PERFORM pg_notify('Notification.sms',
			jsonb_build_object(
				'id', v_sms_id::text,
				'app_id', in_params->>'app_id'
			)::text
		);
	END IF;
	
	IF v_email_note THEN
		PERFORM pg_notify('Notification.email',
			jsonb_build_object(
				'id', v_mail_id::text,
				'app_id', in_params->>'app_id'
			)::text
		);
		
	END IF;
	*/
END;
$$
  LANGUAGE plpgsql VOLATILE
  COST 100;
