    		format('("client","%s")'::text, cl.name::text)::template_value,
    		format('("name","%s")'::text, o.descr)::template_value,
    		format('("tel","%s")'::text,format_cel_phone(o.phone_cel::text))::template_value,
    		format('("car","%s")'::text, vh.plate::text)::template_value
    	],
    	( SELECT t.pattern
           FROM sms_patterns t
          WHERE t.sms_type = 'order_for_pump_ins'::sms_types AND t.lang_id = 1
       )
   ) AS message,
   clients_ref(cl) AS ext_obj
   
   FROM orders o
     LEFT JOIN concrete_types ct ON ct.id = o.concrete_type_id
     LEFT JOIN destinations dest ON dest.id = o.destination_id
     LEFT JOIN pump_vehicles pvh ON pvh.id = o.pump_vehicle_id
     LEFT JOIN vehicles vh ON vh.id = pvh.vehicle_id
     LEFT JOIN clients cl ON cl.id = o.client_id
  WHERE o.pump_vehicle_id IS NOT NULL AND pvh.phone_cel IS NOT NULL AND pvh.phone_cel::text <> ''::text AND o.quant <> 0::double precision;

ALTER TABLE sms_pump_order_ins
  OWNER TO beton;



-- ******************* update 15/04/2022 15:53:55 ******************
﻿-- Function: sms_pump_order_ins(in_order_id int)

 DROP FUNCTION sms_pump_order_ins(in_order_id int);

CREATE OR REPLACE FUNCTION sms_pump_order_ins(in_order_id int)
  RETURNS TABLE(
  	phone_cel text,
  	message text,
  	ext_obj json
  ) AS
$$
	SELECT
		sub.r->'fields'->>'tel' AS tel,
		sub.message AS message,
		sub.ext_obj AS ext_obj
	FROM
	(
	SELECT
		jsonb_array_elements(pvh.phone_cels->'rows') AS r,
		sms_templates_text(
			ARRAY[
		    		format('("quant","%s")'::text, o.quant::text)::template_value,
		    		format('("date","%s")'::text, date5_descr(o.date_time::date)::text)::template_value,
		    		format('("time","%s")'::text, time5_descr(o.date_time::time without time zone)::text)::template_value,
		    		format('("date","%s")'::text, date8_descr(o.date_time::date)::text)::template_value,
		    		format('("dest","%s")'::text, dest.name::text)::template_value,
		    		format('("concrete","%s")'::text, ct.name::text)::template_value,
		    		format('("client","%s")'::text, cl.name::text)::template_value,
		    		format('("name","%s")'::text, o.descr)::template_value,
		    		format('("tel","%s")'::text,format_cel_phone(o.phone_cel::text))::template_value,
		    		format('("car","%s")'::text, vh.plate::text)::template_value
			],
			( SELECT t.pattern
			FROM sms_patterns t
			WHERE t.sms_type = 'order_for_pump_ins'::sms_types AND t.lang_id = 1
			)
		) AS message,
		clients_ref(cl) AS ext_obj
	
	FROM orders o
		LEFT JOIN concrete_types ct ON ct.id = o.concrete_type_id
		LEFT JOIN destinations dest ON dest.id = o.destination_id
		LEFT JOIN pump_vehicles pvh ON pvh.id = o.pump_vehicle_id
		LEFT JOIN vehicles vh ON vh.id = pvh.vehicle_id
		LEFT JOIN clients cl ON cl.id = o.client_id
	WHERE o.id=in_order_id
	) AS sub;
$$
  LANGUAGE sql VOLATILE
  COST 100;
ALTER FUNCTION sms_pump_order_ins(in_order_id int) OWNER TO beton;


-- ******************* update 15/04/2022 16:42:23 ******************
-- View: sms_client_thank

-- DROP VIEW sms_client_thank;

CREATE OR REPLACE VIEW sms_client_thank AS 
	SELECT o.phone_cel,
		get_shift_start(o.date_time) AS shift,
		sms_templates_text(
			ARRAY[
				format('("quant","%s")'::text,
				sum(o.quant)::text)::template_value
			],
			( SELECT t.pattern
			FROM sms_patterns t
			WHERE t.sms_type = 'client_thank'::sms_types AND t.lang_id = 1
			)
		) AS message,
		clients_ref(cl) AS ext_obj
		
	FROM orders o
	LEFT JOIN clients AS cl ON cl.id = o.client_id
	WHERE o.phone_cel IS NOT NULL
		AND o.phone_cel::text <> ''::text
		AND o.quant <> 0::double precision
		AND COALESCE(
			(SELECT sum(sh.quant) AS sum
			FROM shipments sh
			WHERE sh.order_id = o.id),0::double precision
		) > 0::double precision
	GROUP BY o.phone_cel, get_shift_start(o.date_time),cl.*;

ALTER TABLE sms_client_thank
  OWNER TO beton;



-- ******************* update 15/04/2022 16:52:36 ******************
-- View: public.sup_orders_for_sms

-- DROP VIEW public.sup_orders_for_sms;

CREATE OR REPLACE VIEW public.sup_orders_for_sms
 AS
	SELECT
		m.id AS material_id,
		m.name AS material_descr,
		sp.id AS supplier_id,
		sp.name AS supplier_descr,
		sp.tel,
		sp.tel2,
		round(o.quant) AS quant,
		replace(replace(replace(replace(templ.pattern, '[date]'::text, date8_descr((now()::date + '1 day'::interval)::date)::text), '[quant]'::text, round(o.quant)::text), '[mat]'::text, m.name::text), '[sup]'::text, sp.name::text) AS mes_text,
		suppliers_ref(sp) AS ext_obj
		
	FROM supplier_orders o
	LEFT JOIN raw_materials m ON m.id = o.material_id
	LEFT JOIN suppliers sp ON sp.id = o.supplier_id
	LEFT JOIN sms_patterns templ ON templ.sms_type = 'procur'::sms_types
		AND templ.lang_id = coalesce(sp.lang_id, (const_def_lang_val()->'keys'->>'id')::int)
	WHERE o.date = (now()::date + '1 day'::interval)
		AND coalesce(sp.tel::text, '::text') <> ''::text
		AND coalesce(sp.order_notification, FALSE) = TRUE;

ALTER TABLE public.sup_orders_for_sms
    OWNER TO beton;



