-- ******************* update 28/04/2022 08:55:23 ******************
﻿-- Function: orders_complete_descr(in_client_id int, in_descr text)

-- DROP FUNCTION orders_complete_descr(in_client_id int, in_descr text);

CREATE OR REPLACE FUNCTION orders_complete_descr(in_client_id int, in_descr text)
  RETURNS TABLE(
	descr text,
	phone_cel text,
	langs_ref json,
	clients_ref json,
	client_tels_ref json,
	tm_exists bool,
	tm_activated  bool
  ) AS
$$
	WITH
	contacts AS (
		SELECT
			tl.id,
			tl.name,
			tl.tel,
			clients_ref(cl) AS clients_ref,
			client_tels_ref(tl) AS client_tels_ref,
			(e_user.id IS NOT NULL) tm_exists,
			(e_user.tm_id IS NOT NULL) tm_activated

		FROM client_tels AS tl
		LEFT JOIN notifications.ext_users_list AS e_user ON (e_user.ext_obj->'keys'->>'id')::int=tl.id
		LEFT JOIN clients cl ON cl.id=tl.client_id
		WHERE tl.client_id=in_client_id AND (in_descr='' OR lower(tl.name) LIKE lower(in_descr)||'%%')
		ORDER BY tl.name
	),
	o_list AS (
		SELECT DISTINCT ON (o.descr)
				o.descr,
				o.date_time,
				o.phone_cel,
				langs_ref(lg) AS langs_ref,
				ct.id AS contact_id,
