-- VIEW: client_tels_list

--DROP VIEW client_tels_list;

CREATE OR REPLACE VIEW client_tels_list AS
	SELECT
		t.*,
		clients_ref(cl) AS clients_ref,
		(e_user.id IS NOT NULL) AS tm_exists,
		(e_user.tm_id IS NOT NULL) AS tm_activated
		
	FROM client_tels AS t
	LEFT JOIN clients AS cl ON cl.id=t.client_id
	LEFT JOIN notifications.ext_users_list AS e_user ON e_user.ext_obj->>'dataType'='client_tels'
		AND (e_user.ext_obj->'keys'->>'id')::int=t.id
		AND e_user.app_id=1
	ORDER BY t.search
	;
	
ALTER VIEW client_tels_list OWNER TO beton;


-- ******************* update 24/05/2022 13:47:21 ******************
-- Function: public.client_tels_add(in_name text, in_tel text)

-- DROP FUNCTION public.client_tels_add(in_name text, in_tel text);

CREATE OR REPLACE FUNCTION public.client_tels_add(in_name text, in_tel text)
  RETURNS void AS
$BODY$  
DECLARE
	v_id int;  
BEGIN	
	IF coalesce(in_tel,'')='' THEN
		RETURN;
	END IF;	
	
	SELECT id INTO v_id
	FROM client_tels WHERE tel = in_tel;	

	IF v_id IS NOT NULL THEN
		RETURN;
	END IF;
	
	--no contact...
	SELECT id INTO v_id
	FROM clients WHERE rtrim(name) = in_name;
	
	IF v_id	IS NULL THEN
		INSERT INTO clients (name)
		VALUES (in_name) RETURNING id INTO v_id;		
	END IF;

	INSERT INTO client_tels (client_id, name, tel)
	VALUES (v_id, in_name, in_tel);			
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION public.client_tels_add(in_name text, in_tel text) OWNER TO beton;



