	LEFT JOIN (
		SELECT
			tr.car_id,
			max(tr.period) AS period
		FROM car_tracking tr
		GROUP BY tr.car_id
	) AS tr_d ON tr_d.car_id = v.tracker_id
	LEFT JOIN car_tracking AS tr_data ON tr_data.car_id = tr_d.car_id AND tr_data.period = tr_d.period
	*/
	ORDER BY v.plate
	;

