		CASE
			WHEN e_ct.entity_type = 'clients' THEN clients_ref(cl)
			WHEN e_ct.entity_type = 'users' THEN users_ref(u)
			WHEN e_ct.entity_type = 'suppliers' THEN suppliers_ref(spl)
			ELSE NULL
		END AS entities_ref,
