﻿-- Function: sms_new_pwd(in_user_id int, in_pwd text)

 DROP FUNCTION sms_new_pwd(in_user_id int, in_pwd text);

/**
 * Используется именно функция
 * из User_Controller
 */
CREATE OR REPLACE FUNCTION sms_new_pwd(in_user_id int, in_pwd text)
  RETURNS TABLE(
  	phone_cel text,
  	message text,
  	ext_contact_id int
  ) AS
$$
	SELECT
		format_cel_standart(ct.tel) AS tel,
		sms_templates_text(
			ARRAY[
				format('("pwd","%s")'::text, in_pwd)::template_value,
				format('("name","%s")'::text, u.name::text)::template_value
			],
			( SELECT t.pattern
			FROM sms_patterns t
			WHERE t.sms_type = 'new_pwd'::sms_types AND t.lang_id = ((const_def_lang_val())->'keys'->>'id')::int
			)
		) AS message,
		ct.id AS ext_contact_id
	
	FROM users AS u
	LEFT JOIN entity_contacts AS e_ct ON e_ct.entity_type = 'users' AND e_ct.entity_id = in_user_id
	LEFT JOIN contacts AS ct ON ct.id = e_ct.contact_id
	WHERE u.id = in_user_id;	
$$
  LANGUAGE sql VOLATILE
  COST 100;
ALTER FUNCTION sms_new_pwd(in_user_id int, in_pwd text) OWNER TO beton;


-- ******************* update 24/12/2022 08:29:06 ******************
-- View: sms_client_thank

-- DROP VIEW sms_client_thank;

CREATE OR REPLACE VIEW sms_client_thank AS 
	SELECT o.phone_cel,
		get_shift_start(o.date_time) AS shift,
		sms_templates_text(
			ARRAY[
				format('("quant","%s")'::text,
				sum(o.quant)::text)::template_value
			],
			( SELECT t.pattern
			FROM sms_patterns t
			WHERE t.sms_type = 'client_thank'::sms_types AND t.lang_id = 1
			)
		) AS message,
		clients_ref(cl) AS ext_obj,
		ct.id AS ext_contact_id
		
	FROM orders o
	LEFT JOIN clients AS cl ON cl.id = o.client_id
	LEFT JOIN contacts AS ct ON ct.id = o.contact_id
	WHERE o.phone_cel IS NOT NULL
		AND o.phone_cel::text <> ''::text
		AND o.quant <> 0::double precision
		AND COALESCE(
			(SELECT
				sum(sh.quant) AS sum
			FROM shipments sh
			WHERE sh.order_id = o.id
			),0::double precision
		) > 0::double precision
	GROUP BY o.phone_cel,
		get_shift_start(o.date_time),
		cl.*,
		ct.id;

ALTER TABLE sms_client_thank
  OWNER TO beton;



