--DROP VIEW raw_material_ticker_carrier_agg_list;

CREATE OR REPLACE VIEW raw_material_ticker_carrier_agg_list AS
	WITH
	sel AS (
		SELECT
			carrier_id,
			raw_material_id,
			quant,
			count(*) * quant AS quant_tot
		FROM raw_material_tickets
		GROUP BY carrier_id, raw_material_id, quant
	)
	SELECT
		suppliers_ref(sp) AS carriers_ref,
		materials_ref(mat) AS raw_materials,
		sel.quant,
		sel.quant_tot
	FROM sel
	LEFT JOIN suppliers AS sp ON sp.id = sel.carrier_id
	LEFT JOIN raw_materials AS mat ON mat.id = sel.raw_material_id
	ORDER BY sp.name, mat.name
	;
	
