-- ******************* update 06/02/2023 10:44:59 ******************
-- FUNCTION: public.order_process()

-- DROP FUNCTION IF EXISTS public.order_process();

CREATE OR REPLACE FUNCTION public.order_process()
    RETURNS trigger
    LANGUAGE 'plpgsql'
    COST 100
    VOLATILE NOT LEAKPROOF
AS $BODY$
DECLARE
	v_contact_name text;
BEGIN
	IF (TG_OP='INSERT') OR ((TG_OP='UPDATE') AND (NEW.date_time::date!=OLD.date_time::date)) THEN
		SELECT coalesce(MAX(number),0)+1
		INTO NEW.number
		FROM orders AS o WHERE o.date_time::date=NEW.date_time::date;		
	END IF;
	
	IF TG_OP='INSERT' THEN
		NEW.last_modif_user_id = NEW.user_id;		
	END IF;
	NEW.last_modif_date_time = now();
	
	NEW.date_time_to = get_order_date_time_to(NEW.date_time,NEW.quant::numeric, NEW.unload_speed::numeric, const_order_step_min_val());

	IF NEW.lang_id IS NULL THEN
		NEW.lang_id = 1;
	END IF;
	
	
	IF NEW.contact_id IS NULL AND coalesce(NEW.phone_cel, '') <> '' THEN
		-- no contact
		SELECT
			ct.id,
			ct.name::text
		INTO
			NEW.contact_id,
			v_contact_name
		FROM contacts AS ct
		WHERE ct.tel = format_cel_standart(NEW.phone_cel);
		
		IF NEW.contact_id IS NULL THEN
			v_contact_name = coalesce(NEW.descr, '');
			IF v_contact_name = '' THEN
				SELECT cl.name INTO v_contact_name FROM clients AS cl
				WHERE cl.id = NEW.client_id;
			END IF;
		
			INSERT INTO contacts (name, tel)
			VALUES (v_contact_name, NEW.phone_cel)
			ON CONFLICT (tel) DO UPDATE SET name = v_contact_name
			RETURNING id INTO NEW.contact_id;
		END IF;
	END IF;
	
	-- а есть ли контакт у клиента?
	IF coalesce(
		(SELECT TRUE
		FROM entity_contacts AS e_ct
		WHERE e_ct.contact_id = NEW.contact_id AND e_ct.entity_type = 'clients' AND e_ct.entity_id = NEW.client_id)
		,FALSE) = FALSE THEN
		
		INSERT INTO entity_contacts (entity_type, entity_id, contact_id)
		VALUES ('clients', NEW.client_id, NEW.contact_id)
		ON CONFLICT (entity_type, entity_id, contact_id) DO NOTHING;
	END IF;
	
	/*
	round_minutes(New.date_time +
		to_char( (floor(60* NEW.quant/NEW.unload_speed)::text || ' minutes')::interval, 'HH24:MI')::interval,
		const_order_step_min_val()
		);
	*/
	--RAISE 'v_end_time_min=%',NEW.time_to;
	
	RETURN NEW;
END;
$BODY$;

ALTER FUNCTION public.order_process() OWNER TO beton;



-- ******************* update 06/02/2023 17:37:31 ******************
-- VIEW: entity_contacts_list

--DROP VIEW entity_contacts_list;

CREATE OR REPLACE VIEW entity_contacts_list AS
	SELECT
		e_ct.id ,
		e_ct.entity_type,
		e_ct.entity_id,
		CASE
			WHEN e_ct.entity_type = 'clients' THEN clients_ref(cl)
			WHEN e_ct.entity_type = 'users' THEN users_ref(u)
			WHEN e_ct.entity_type = 'suppliers' THEN suppliers_ref(spl)
			WHEN e_ct.entity_type = 'drivers' THEN drivers_ref(drv)
			WHEN e_ct.entity_type = 'pump_vehicles' THEN pump_vehicles_ref(
				pvh,
				v,
				(SELECT vh_o FROM vehicle_owners AS vh_o
				WHERE vh_o.id = 
					(SELECT
						CASE WHEN owners.r->'fields'->'owner'->'keys'->>'id'='null' THEN NULL
							ELSE (owners.r->'fields'->'owner'->'keys'->>'id')::int
						END	
					FROM
					(
						SELECT jsonb_array_elements(v.vehicle_owners->'rows') AS r
					) AS owners
					ORDER BY owners.r->'fields'->'dt_from' DESC
					LIMIT 1
					)			
				)				
			)
			ELSE NULL
		END AS entities_ref,
		e_ct.contact_id,
		contacts_ref(ct) AS contacts_ref,
		json_build_object(
			'name', ct.name,
			'tel', ct.tel,
			'email', ct.email,
			'tel_ext', ct.tel_ext,
			'post', p.name
		) AS contact_attrs,
		
		(e_user.id IS NOT NULL) AS tm_exists,
		(e_user.tm_id IS NOT NULL) AS tm_activated
		
		
	FROM entity_contacts AS e_ct
	LEFT JOIN clients AS cl ON e_ct.entity_type = 'clients' AND cl.id = e_ct.entity_id
	LEFT JOIN users AS u ON e_ct.entity_type = 'users' AND u.id = e_ct.entity_id
	LEFT JOIN suppliers AS spl ON e_ct.entity_type = 'suppliers' AND spl.id = e_ct.entity_id
	LEFT JOIN pump_vehicles AS pvh ON e_ct.entity_type = 'pump_vehicles' AND pvh.id = e_ct.entity_id
	LEFT JOIN vehicles AS v ON v.id = pvh.vehicle_id
	LEFT JOIN drivers AS drv ON e_ct.entity_type = 'drivers' AND drv.id = e_ct.entity_id
	LEFT JOIN contacts AS ct ON ct.id = e_ct.contact_id
	LEFT JOIN posts AS p ON p.id = ct.post_id
	
	LEFT JOIN notifications.ext_users_list AS e_user ON e_user.app_id = 1 AND e_user.ext_contact_id = e_ct.entity_id
	/*LEFT JOIN notifications.ext_users_list AS e_user ON e_user.ext_obj->>'dataType'='contacts'
		AND (e_user.ext_obj->'keys'->>'id')::int = e_ct.contact_id
		AND e_user.app_id=1
	*/	
	
	ORDER BY e_ct.entity_type,
		CASE
			WHEN e_ct.entity_type = 'clients' THEN clients_ref(cl)->>'descr'
			WHEN e_ct.entity_type = 'users' THEN users_ref(u)->>'descr'
			WHEN e_ct.entity_type = 'suppliers' THEN suppliers_ref(spl)->>'descr'
			WHEN e_ct.entity_type = 'drivers' THEN drivers_ref(drv)->>'descr'
			WHEN e_ct.entity_type = 'pump_vehicles' THEN pump_vehicles_ref(
				pvh,
				v,
				(SELECT vh_o FROM vehicle_owners AS vh_o
				WHERE vh_o.id = 
					(SELECT
						CASE WHEN owners.r->'fields'->'owner'->'keys'->>'id'='null' THEN NULL
							ELSE (owners.r->'fields'->'owner'->'keys'->>'id')::int
						END	
					FROM
					(
						SELECT jsonb_array_elements(v.vehicle_owners->'rows') AS r
					) AS owners
					ORDER BY owners.r->'fields'->'dt_from' DESC
					LIMIT 1
					)			
				)				
			)->>'descr'
			ELSE NULL
		END
	;
	
ALTER VIEW entity_contacts_list OWNER TO beton;


