		,CASE WHEN sum(sub.concrete_quant)=0 THEN 0 ELSE round( sum(sub.norm_cost) / sum(sub.concrete_quant) ,2) END AS norm_cost_per_m3

		,sum(sub.material_quant) AS material_quant
