	WHERE t.date_time BETWEEN in_date_time_from AND in_date_time_to
	--'2020-07-19 06:00' AND '2020-07-20 06:00'
	--AND t.raw_material_id=7
	GROUP BY 
		--sh.id
		prod.production_id
		,t.concrete_type_id	
		,t.raw_material_id
		,mat.name
