			jsonb_build_object(
				'id', sub.role_id,
				'descr', get_role_types_descr(sub.role_id)
			)
		)		
	FROM (
		SELECT DISTINCT
			u.role_id
		FROM entity_contacts AS u_ct
		LEFT JOIN users AS u On u.id = u_ct.entity_id
		WHERE
			u_ct.contact_id=(select contact_id from entity_contacts where entity_type='users' and entity_id=80)
			AND u_ct.entity_type='users'
			and u_ct.entity_id<>80
	) AS sub
	;
$$
  LANGUAGE sql VOLATILE
  COST 100;
