-- View: public.shipments_list

--DROP VIEW shipments_for_veh_owner_list;
--DROP VIEW shipment_dates_list;
--DROP VIEW public.shipments_list;

CREATE OR REPLACE VIEW public.shipments_list AS 
	SELECT
		sh.id,
		sh.ship_date_time,
		sh.quant,
		
		--shipments_cost(dest,o.concrete_type_id,o.date_time::date,sh,TRUE) AS cost,
		(CASE
			-- Вручную из документа
			WHEN coalesce(sh.ship_cost_edit, FALSE) THEN sh.ship_cost
			
			-- Самовывоз
			WHEN dest.id=const_self_ship_dest_id_val() THEN 0
			
			-- Вода
			WHEN o.concrete_type_id=12 THEN
				--const_water_ship_cost_val()
				water_ship_cost_on_date(sh.date_time)
				
			-- Все остальное
			ELSE
				CASE
					-- цена по производственным зонам
					WHEN destination_prod_base_price_val(ps.production_base_id, dest.id, sh.ship_date_time::timestamp) IS NOT NULL THEN
						destination_prod_base_price_val(ps.production_base_id, dest.id, sh.ship_date_time::timestamp)
				
					-- специальная цена
					WHEN coalesce(dest.special_price, FALSE) THEN
						coalesce(period_value('destination_price'::period_value_types, dest.id, sh.date_time)::numeric(15,2),0)
						
					-- по схеме от расстояния
					ELSE
						coalesce(
							(SELECT sh_p.price
							FROM shipment_for_owner_costs sh_p
							WHERE sh_p.date<=o.date_time::date AND sh_p.distance_to>=dest.distance
							ORDER BY sh_p.date DESC,sh_p.distance_to ASC
							LIMIT 1
							)			
							,coalesce(dest.price, 0)
						)
				END
				*
				shipments_quant_for_cost(sh.ship_date_time::date,sh.quant::numeric,dest.distance::numeric)
		END)::numeric(15,2)
		AS cost,
		
		sh.shipped,
		concrete_types_ref(concr) AS concrete_types_ref,
		o.concrete_type_id,		
		v.owner,
		
		vehicles_ref(v) AS vehicles_ref,
		vs.vehicle_id,
		
		drivers_ref(d) AS drivers_ref,
		vs.driver_id,
		
		destinations_ref(dest) As destinations_ref,
		o.destination_id,
		
		clients_ref(cl) As clients_ref,
		o.client_id,
		
		shipments_demurrage_cost(sh.demurrage::interval, sh.date_time) AS demurrage_cost,
		sh.demurrage,
		
		sh.client_mark,
		sh.blanks_exist,
		
		users_ref(u) As users_ref,
		o.user_id,
		
		production_sites_ref(ps) AS production_sites_ref,
		sh.production_site_id,
		
		--vehicle_owners_ref(v_own) AS vehicle_owners_ref,
		vehicle_owner_on_date(v.vehicle_owners,sh.date_time) AS vehicle_owners_ref,
		
		sh.acc_comment,
		sh.acc_comment_shipment,
		--v_own.id AS vehicle_owner_id,
		((vehicle_owner_on_date(v.vehicle_owners,sh.date_time))->'keys'->>'id')::int AS vehicle_owner_id,
		
		--shipments_pump_cost(sh,o,dest,pvh,TRUE) AS pump_cost,
		(SELECT
			CASE
				WHEN o.pump_vehicle_id IS NULL THEN 0
				WHEN coalesce(sh.pump_cost_edit,FALSE) THEN sh.pump_cost::numeric(15,2)
				--last ship only!!!
				WHEN sh.id = (SELECT this_ship.id FROM shipments AS this_ship WHERE this_ship.order_id=o.id ORDER BY this_ship.ship_date_time DESC LIMIT 1)
				THEN
					CASE
						WHEN coalesce(o.total_edit,FALSE) AND coalesce(o.unload_price,0)>0 THEN o.unload_price::numeric(15,2)
						ELSE
							(SELECT
								CASE
									WHEN coalesce(pr_vals.price_fixed,0)>0 THEN pr_vals.price_fixed
									ELSE coalesce(pr_vals.price_m,0)*o.quant
								END
							FROM pump_prices_values AS pr_vals
							WHERE pr_vals.pump_price_id = (pump_vehicle_price_on_date(pvh.pump_prices,sh.date_time)->'keys'->>'id')::int
								--pvh.pump_price_id
								AND o.quant<=pr_vals.quant_to
							ORDER BY pr_vals.quant_to ASC
							LIMIT 1
							)::numeric(15,2)
					END
				ELSE 0	
			END
		) AS pump_cost,
		
		pump_vehicles_ref(pvh,pvh_v,pvh_own) AS pump_vehicles_ref,
		pvh.vehicle_id AS pump_vehicle_id,
		pvh_v.vehicle_owner_id AS pump_vehicle_owner_id,
		sh.owner_agreed,
		sh.owner_agreed_date_time,
		sh.owner_pump_agreed,
		sh.owner_pump_agreed_date_time,
		
		vehicle_owners_ref(pvh_own) AS pump_vehicle_owners_ref,
		
		CASE
			-- цена по производственным зонам
			WHEN destination_prod_base_price_val(ps.production_base_id, dest.id, sh.ship_date_time::timestamp) IS NOT NULL THEN
				destination_prod_base_price_val(ps.production_base_id, dest.id, sh.ship_date_time::timestamp)
		
			WHEN coalesce(dest.special_price,FALSE) THEN
				coalesce(
					period_value('destination_price'::period_value_types, dest.id, sh.date_time)::numeric(15,2),
					0
				)
			ELSE
				coalesce(
					(SELECT sh_p.price
					FROM shipment_for_owner_costs sh_p
					WHERE sh_p.date<=o.date_time::date AND sh_p.distance_to>=dest.distance
					ORDER BY sh_p.date DESC,sh_p.distance_to ASC
					LIMIT 1
					),			
					coalesce(dest.price,0)
				)			
		END AS ship_price,
		
		coalesce(sh.ship_cost_edit,FALSE) AS ship_cost_edit,
		coalesce(sh.pump_cost_edit,FALSE) AS pump_cost_edit,
		
		sh.pump_for_client_cost_edit,
		(SELECT
			CASE
				WHEN o.pump_vehicle_id IS NULL THEN 0
				WHEN coalesce(sh.pump_for_client_cost_edit,FALSE) THEN sh.pump_for_client_cost::numeric(15,2)
				--last ship only!!!
				WHEN sh.id = (SELECT this_ship.id FROM shipments AS this_ship WHERE this_ship.order_id=o.id ORDER BY this_ship.ship_date_time DESC LIMIT 1)
				THEN
					CASE
						WHEN coalesce(o.total_edit,FALSE) AND coalesce(o.unload_price,0)>0 THEN o.unload_price::numeric(15,2)
						ELSE
							(SELECT
								CASE
									WHEN coalesce(pr_vals.price_fixed,0)>0 THEN pr_vals.price_fixed
									ELSE coalesce(pr_vals.price_m,0)*o.quant
								END
							FROM pump_prices_values AS pr_vals
							WHERE pr_vals.pump_price_id = (pump_vehicle_price_on_date(pvh.pump_prices,sh.date_time)->'keys'->>'id')::int
								--pvh.pump_price_id
								AND o.quant<=pr_vals.quant_to
							ORDER BY pr_vals.quant_to ASC
							LIMIT 1
							)::numeric(15,2)
					END
				ELSE 0	
			END
		) AS pump_for_client_cost
		
		/*,prod.production_id
		,concrete_types_ref(prod_concr) AS production_concrete_types_ref
		,prod.concrete_quant AS production_concrete_quant
		*/
		
	FROM shipments sh
	LEFT JOIN orders o ON o.id = sh.order_id
	LEFT JOIN concrete_types concr ON concr.id = o.concrete_type_id
	LEFT JOIN clients cl ON cl.id = o.client_id
	LEFT JOIN vehicle_schedules vs ON vs.id = sh.vehicle_schedule_id
	LEFT JOIN destinations dest ON dest.id = o.destination_id
	LEFT JOIN drivers d ON d.id = vs.driver_id
	LEFT JOIN vehicles v ON v.id = vs.vehicle_id
	LEFT JOIN users u ON u.id = sh.user_id
	LEFT JOIN production_sites ps ON ps.id = sh.production_site_id
	LEFT JOIN vehicle_owners v_own ON v_own.id = v.vehicle_owner_id
	LEFT JOIN pump_vehicles pvh ON pvh.id = o.pump_vehicle_id
	LEFT JOIN vehicles pvh_v ON pvh_v.id = pvh.vehicle_id
	LEFT JOIN vehicle_owners pvh_own ON pvh_own.id = pvh_v.vehicle_owner_id
	
	/*LEFT JOIN (
		SELECT
			t.shipment_id,
			t.production_id,
			t.concrete_type_id,
			sum(concrete_quant)::numeric(19,4) AS concrete_quant
		FROM productions AS t
		GROUP BY t.shipment_id,t.production_id,t.concrete_type_id
	) AS prod ON prod.shipment_id = sh.id
	LEFT JOIN concrete_types AS prod_concr ON prod_concr.id = prod.concrete_type_id
	*/
	ORDER BY sh.date_time DESC
	--LIMIT 60
	;

ALTER TABLE public.shipments_list OWNER TO beton;



-- ******************* update 18/07/2023 09:20:18 ******************
-- FUNCTION: public.get_vehicle_statistics(date)

-- DROP FUNCTION IF EXISTS public.get_vehicle_statistics(date);

CREATE OR REPLACE FUNCTION public.get_vehicle_statistics(
	in_date date)
    RETURNS TABLE(key text, val text) 
    LANGUAGE 'plpgsql'
    COST 100
    VOLATILE PARALLEL UNSAFE
    ROWS 1000

AS $BODY$
DECLARE
	ROUND_AVG_MINUTES int = 5;
	ROUND_MIN_MINUTES int = 30;

	v_date_time_from timestamp;
	v_date_time_from_shift_start timestamp;
	v_date_time_to timestamp;
	v_round_avg_interval interval;
	v_round_min_interval interval;
	v_avg_interval_count int;
	
	v_at_base_avg interval;
	v_work_avg interval;
	v_run_avg interval;
	v_at_dest_avg interval;
	v_end_time_interval interval;
	v_first_shift_start_interval interval;
	v_day_shift_length_interval interval;	
BEGIN
	/*
		All statistics data from 8-00(constant_first_shift_start_time+01:00) to 20-00
		
	*/
	v_date_time_from_shift_start = in_date +constant_first_shift_start_time()::interval;
	v_date_time_from =  v_date_time_from_shift_start + '01:00'::interval;
	v_first_shift_start_interval = constant_first_shift_start_time()::interval;
	v_day_shift_length_interval = constant_day_shift_length()::interval;
	
	IF (in_date<>CURRENT_DATE) THEN
		v_end_time_interval = v_day_shift_length_interval;
		v_date_time_to = v_date_time_from + v_end_time_interval;
		v_avg_interval_count = ceil(EXTRACT(EPOCH FROM v_end_time_interval/(ROUND_AVG_MINUTES*60) ))::int;		
		
	ELSE
		v_date_time_to = LEAST(CURRENT_TIMESTAMP::timestamp without time zone, in_date + v_first_shift_start_interval+v_day_shift_length_interval);
		--13 hours *60*60 = 46800sec/ (5min*60sec) = 156
		v_avg_interval_count = ceil(EXTRACT(EPOCH FROM (v_date_time_to::time-v_first_shift_start_interval)/(ROUND_AVG_MINUTES*60) ))::int;		
		v_end_time_interval = LEAST(CURRENT_TIMESTAMP::time::interval-v_first_shift_start_interval, v_day_shift_length_interval);
	END IF;
	
	v_date_time_to = round_minutes(v_date_time_to, ROUND_AVG_MINUTES);	
	
	v_round_avg_interval = (ROUND_AVG_MINUTES || ' minutes ')::interval;
	v_round_min_interval = (ROUND_MIN_MINUTES || ' minutes ')::interval;

	--************************************** FROM 7-00 ***********************************
	SELECT date_trunc('second',AVG(tm)) INTO v_at_base_avg FROM at_base_time(v_date_time_from_shift_start,v_date_time_to);
	SELECT date_trunc('second',AVG(tm)) INTO v_run_avg FROM at_run_time(v_date_time_from_shift_start,v_date_time_to);
	SELECT date_trunc('second',AVG(tm)) INTO v_work_avg FROM at_work_time(v_date_time_from_shift_start,v_date_time_to);
	SELECT date_trunc('second',AVG(tm)) INTO v_at_dest_avg FROM at_dest_time(v_date_time_from_shift_start,v_date_time_to);
	--*********************************************************

	
	RETURN QUERY
		WITH veh_cnt AS (
			SELECT d,
			(SELECT ARRAY[busy_cnt,free_cnt] FROM veh_count_at_moment(d)) AS all_cnt
			FROM generate_series(v_date_time_from, v_date_time_to, v_round_avg_interval) AS d		
		),
		min_time AS (
			SELECT m.d_30
			FROM(
				SELECT d_30,AVG(cnt.all_cnt[2]) AS avg_30
				FROM generate_series(v_date_time_from, v_date_time_to, v_round_min_interval) AS d_30
				LEFT JOIN (SELECT * FROM veh_cnt) AS cnt ON cnt.d>=d_30 AND cnt.d<(d_30+v_round_min_interval)
				GROUP BY d_30
			) AS m
			ORDER BY m.avg_30 LIMIT 1
		),
		min_time_descr AS (SELECT time5_descr(d_30::time)::text || '-' || time5_descr((d_30+v_round_min_interval)::time)::text AS descr FROM min_time)

		SELECT
		'Среднее кол. свободных автом. (' || ROUND_AVG_MINUTES::text || ' мин.)' AS key,
		(SELECT round(SUM(all_cnt[2])/v_avg_interval_count,2)::text FROM veh_cnt) AS val

		UNION ALL

		SELECT
		'Среднее кол. занятых автом. (' || ROUND_AVG_MINUTES::text || ' мин.)' AS key,
		(SELECT round(SUM(all_cnt[1])/v_avg_interval_count,2)::text FROM veh_cnt) AS val

		UNION ALL

		SELECT
		'Макс. автом. на базе в миним. получасе ' || (SELECT descr FROM min_time_descr) AS key,
		(SELECT MAX(all_cnt[2])::text FROM veh_cnt WHERE d>=(SELECT d_30 FROM min_time) AND d<((SELECT d_30 FROM min_time)+v_round_avg_interval)) AS val

		UNION ALL

		SELECT
		'Дозаказать автомашин на завтра' AS key,
		(SELECT get_required_veh_count())::text AS val
		
		UNION ALL

		SELECT
		'Среднее время рейса' AS key,
		time5_descr(v_run_avg::time)::text AS val
			

		UNION ALL

		SELECT
		'Среднее время на объекте' AS key,
		time5_descr(v_at_dest_avg::time)::text AS val

		UNION ALL

		SELECT
		'Среднее время на базе' AS key,
		time5_descr(v_at_base_avg::time)::text AS val

		UNION ALL

		SELECT
		'Коэф-нт среднего на базе к раб. времени ' || time5_descr(v_at_base_avg::time)::text || '/' || time5_descr(v_work_avg::time)::text AS key,
		(
			round( (EXTRACT(EPOCH FROM v_at_base_avg)/EXTRACT(EPOCH FROM v_work_avg))::numeric ,2)*100::numeric
		)::text || ' %' AS val

		UNION ALL

		SELECT
		'Коэф-нт рабочего времени ко всему времени ' || time5_descr(v_work_avg::time)::text || '/' || time5_descr(v_end_time_interval::time)::text AS key,
		(
			round( (EXTRACT(EPOCH FROM v_work_avg)/EXTRACT(EPOCH FROM v_end_time_interval))::numeric ,2)*100::numeric
		)::text || ' %' AS val;
		

		
END;
$BODY$;

