-- ******************* update 18/07/2023 12:10:31 ******************
-- Function: public.material_fact_balance_corrections_process()

-- DROP FUNCTION public.material_fact_balance_corrections_process();

CREATE OR REPLACE FUNCTION public.material_fact_balance_corrections_process()
  RETURNS trigger AS
$BODY$
DECLARE
	reg_material_facts ra_material_facts%ROWTYPE;
	reg_cement ra_cement%ROWTYPE;
	add_quant numeric(19,4);
	ra_date_time timestamp;	
	v_is_cement bool;
	v_dif_store bool;
	v_production_base_id int;
BEGIN
	IF TG_WHEN='BEFORE' AND TG_OP='INSERT' THEN
		IF NEW.balance_date_time IS NULL THEN
			NEW.balance_date_time = get_shift_start(NEW.date_time);
		END IF;
		
		RETURN NEW;
		
	ELSIF (TG_WHEN='AFTER' AND (TG_OP='INSERT' OR TG_OP='UPDATE') ) THEN
		IF (TG_OP='INSERT') THEN						
			--log
			PERFORM doc_log_insert('material_fact_balance_correction'::doc_types,NEW.id,NEW.balance_date_time-'1 second'::interval);
		END IF;

		ra_date_time = NEW.balance_date_time-'1 second'::interval;
		
		--attributes
		SELECT
			is_cement
			,dif_store
		INTO
			v_is_cement
			,v_dif_store
		FROM raw_materials
		WHERE id=NEW.material_id;
		
		IF v_is_cement THEN
			--ЦЕМЕНТ
			RAISE EXCEPTION 'Остатки по материалам, учитываемым в силосах, корректируются в разрезе силосов!';
		--ELSIF v_dif_store AND NEW.production_site_id IS NULL THEN
		--	RAISE EXCEPTION 'По материалу % ведется учет остатков в разрезе мест хранения!',(SELECT name FROM raw_materials WHERE id=NEW.material_id);
		ELSIF NEW.production_site_id IS NULL THEN
			RAISE EXCEPTION 'Укажите завод!';
		ELSE 		
			SELECT
				production_base_id
			INTO
				v_production_base_id
			FROM production_sites
			WHERE id = NEW.production_site_id;
			
			IF v_dif_store THEN
				--different query
				add_quant = coalesce((SELECT quant FROM rg_material_facts_balance(ra_date_time, ARRAY[NEW.production_site_id],ARRAY[NEW.material_id])),0);
			ELSE
				-- завод не учитывается!!!
				-- только база
				add_quant = coalesce(
					(SELECT quant FROM rg_material_facts_balance(
						ra_date_time,
						ARRAY[v_production_base_id],
						'{}',
						ARRAY[NEW.material_id])
					)
				,0);
			END IF;
			add_quant = add_quant - NEW.required_balance_quant;
			
			--RAISE EXCEPTION 'BALANCE=%',add_quant;
			IF add_quant <> 0 THEN
				--RAISE EXCEPTION 'add_quant=%',add_quant;
				--register actions ra_material_facts		
				reg_material_facts.date_time		= ra_date_time;
				reg_material_facts.deb			= (add_quant<0);
				reg_material_facts.doc_type  		= 'material_fact_balance_correction'::doc_types;
				reg_material_facts.doc_id  		= NEW.id;
				reg_material_facts.material_id		= NEW.material_id;
				reg_material_facts.production_site_id	= CASE WHEN v_dif_store THEN NEW.production_site_id ELSE NULL END;
				reg_material_facts.production_base_id	= v_production_base_id;
				reg_material_facts.quant		= abs(add_quant);
				PERFORM ra_material_facts_add_act(reg_material_facts);	
			END IF;
		END IF;
		
		--Event support
		PERFORM pg_notify(
				'RAMaterialFact.change'
			,json_build_object(
				'params',json_build_object(
					'cond_date',NEW.date_time::date
				)
			)::text
		);
		
		RETURN NEW;
		
	ELSEIF (TG_WHEN='BEFORE' AND TG_OP='UPDATE') THEN
		IF NEW.balance_date_time<>OLD.balance_date_time THEN
			PERFORM doc_log_update('material_fact_balance_correction'::doc_types,NEW.id,NEW.balance_date_time-'1 second'::interval);
		END IF;

		PERFORM ra_material_facts_remove_acts('material_fact_balance_correction'::doc_types,OLD.id);
		PERFORM ra_cement_remove_acts('material_fact_balance_correction'::doc_types,OLD.id);
		
		RETURN NEW;
		
	ELSEIF TG_OP='DELETE' THEN
		IF TG_WHEN='BEFORE' THEN		
			--log
			PERFORM doc_log_delete('material_fact_balance_correction'::doc_types,OLD.id);

			PERFORM ra_material_facts_remove_acts('material_fact_balance_correction'::doc_types,OLD.id);
			PERFORM ra_cement_remove_acts('material_fact_balance_correction'::doc_types,OLD.id);
		ELSE
			--Event support
			PERFORM pg_notify(
					'RAMaterialFact.change'
				,json_build_object(
					'params',json_build_object(
						'cond_date',OLD.date_time::date
					)
				)::text
			);		
		END IF;
	
		RETURN OLD;
	END IF;
	
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION public.material_fact_balance_corrections_process()
  OWNER TO beton;



-- ******************* update 07/08/2023 07:32:26 ******************
-- Теперь с 09/06/23 еще и разделение по производству
-- FUNCTION: public.material_actions_prod_base3(without time zone, timestamp without time zone)

-- DROP FUNCTION IF EXISTS public.material_actions_prod_base3(timestamp without time zone, timestamp without time zone);

CREATE OR REPLACE FUNCTION public.material_actions_prod_base3(
	in_date_time_from timestamp without time zone,
	in_date_time_to timestamp without time zone)
    RETURNS TABLE(
    	is_cement boolean,
    	material_name text,
    	quant_start numeric,
    	quant_deb numeric,
    	quant_kred numeric,
    	pr1_quant_kred numeric,
    	quant_correction numeric,
    	quant_end numeric
    ) 
    LANGUAGE 'sql'
    COST 100
    VOLATILE PARALLEL UNSAFE
    ROWS 1000

AS $BODY$
	WITH
	prod_base AS (SELECT 3 AS id),
	prod_base_silos AS (
	SELECT
		sl.id
	FROM cement_silos AS sl
	WHERE sl.production_site_id IN (SELECT pst.id from production_sites AS pst WHERE pst.production_base_id = (SELECT prod_base.id FROM prod_base))	
	)
	--По цементу
	(
	SELECT
		TRUE AS is_cement,
		sil.name::text AS material_name,
		coalesce(bal_start.quant,0) AS quant_start,	
		coalesce(ra_deb.quant,0) AS quant_deb,
		coalesce(ra_kred.quant,0) AS quant_kred,
		coalesce(ra_kred.pr1_quant,0) AS pr1_quant_kred,
		coalesce(ra_deb.quant_correction,0)-coalesce(ra_kred.quant_correction,0) AS quant_correction,
		coalesce(bal_start.quant,0)+coalesce(ra_deb.quant,0)+coalesce(ra_deb.quant_correction,0)-coalesce(ra_kred.quant,0)-coalesce(ra_kred.quant_correction,0) AS quant_end
	FROM cement_silos AS sil	
	
	--остаток нач: только силосы по базе 1
	LEFT JOIN (SELECT * FROM rg_cement_balance(
			in_date_time_from,
			(SELECT array_agg(prod_base_silos.id) FROM prod_base_silos)
		)
	) AS bal_start ON bal_start.cement_silos_id=sil.id
	
	--Приход
	LEFT JOIN (
		SELECT
			ra.cement_silos_id,
			sum(
				CASE
					WHEN doc_type='cement_silo_balance_reset' THEN 0
					ELSE ra.quant
				END
			) AS quant,
			sum(
				CASE
					WHEN doc_type='cement_silo_balance_reset' THEN ra.quant
					ELSE 0
				END
			) AS quant_correction
			
		FROM ra_cement AS ra
		LEFT JOIN cement_silos AS sl ON sl.id = ra.cement_silos_id
		WHERE ra.date_time BETWEEN in_date_time_from AND in_date_time_to AND ra.deb AND ra.cement_silos_id IN (SELECT prod_base_silos.id FROM prod_base_silos)
		GROUP BY ra.cement_silos_id
	) AS ra_deb ON ra_deb.cement_silos_id = sil.id 
	
	--Расход
	LEFT JOIN (
		SELECT
			ra.cement_silos_id,
			sum(
				CASE
					WHEN ra.doc_type<>'cement_silo_balance_reset' THEN ra.quant
					ELSE 0
				END
			) AS quant,
			sum(
				CASE
					WHEN ra.doc_type='cement_silo_balance_reset' THEN ra.quant
					ELSE 0
				END
			) AS quant_correction,
			sum(
				CASE
					WHEN ra.doc_type<>'cement_silo_balance_reset' AND sl.production_site_id=5 THEN ra.quant
					ELSE 0
				END
			) AS pr1_quant

		FROM ra_cement AS ra
		LEFT JOIN cement_silos AS sl ON sl.id = ra.cement_silos_id
		WHERE ra.date_time BETWEEN in_date_time_from AND in_date_time_to AND NOT ra.deb AND ra.cement_silos_id IN (SELECT prod_base_silos.id FROM prod_base_silos)
		GROUP BY ra.cement_silos_id
	) AS ra_kred ON ra_kred.cement_silos_id = sil.id 
	WHERE sil.id IN (SELECT prod_base_silos.id FROM prod_base_silos)
	ORDER BY sil.name
	)
	
	UNION ALL
	
	--По материалам без складов
	(
	SELECT
		FALSE AS is_cement,
		m.name,
		coalesce(bal_start.quant,0) AS quant_start,
		coalesce(ra_deb.quant,0) AS quant_deb,
		coalesce(ra_kred.quant,0) AS quant_kred,
		coalesce(ra_kred.pr1_quant,0) AS pr1_quant_kred,
		coalesce(ra_deb.quant_correction,0)-coalesce(ra_kred.quant_correction,0) AS quant_correction,
		coalesce(bal_start.quant,0)+coalesce(ra_deb.quant,0)+coalesce(ra_deb.quant_correction,0)-coalesce(ra_kred.quant,0)-coalesce(ra_kred.quant_correction,0) AS quant_end
	
	FROM raw_materials AS m
	
	--остаток нач
	LEFT JOIN (
		SELECT
			t_rg.*
		FROM rg_material_facts_balance(
			in_date_time_from,
			(SELECT array_agg(prod_base.id) FROM prod_base),
			'{}',
			'{}'
		) AS t_rg
	) AS bal_start ON bal_start.material_id = m.id
	
	--Приход
	LEFT JOIN (
		SELECT
			ra.material_id,
			sum(
				CASE
					WHEN ra.doc_type='material_fact_balance_correction' THEN 0
					ELSE ra.quant
				END
			) AS quant,
			sum(
				CASE
					WHEN ra.doc_type='material_fact_balance_correction' THEN ra.quant
					ELSE 0
				END
			) AS quant_correction
			
		FROM ra_material_facts AS ra
		WHERE ra.date_time BETWEEN in_date_time_from AND in_date_time_to AND ra.deb AND ra.production_base_id = (SELECT prod_base.id FROM prod_base)
		GROUP BY ra.material_id
	) AS ra_deb ON ra_deb.material_id = m.id 
	
	--Расход
	LEFT JOIN (
		SELECT
			ra.material_id,
			sum(
				CASE
					WHEN ra.doc_type='material_fact_balance_correction' THEN 0
					ELSE ra.quant
				END
			) AS quant,
			sum(
				CASE
					-- OR ra.doc_type='material_fact_consumption_correction'
					WHEN doc_type='material_fact_balance_correction' THEN ra.quant
					ELSE 0
				END
			) AS quant_correction,
			sum(
				CASE
					WHEN (ra.doc_type='material_fact_consumption' AND cons.production_site_id = 5)
						OR
						(ra.doc_type='material_fact_consumption_correction' AND cons_cor.production_site_id = 5)
						THEN ra.quant
					ELSE 0
				END
			) AS pr1_quant
			
		FROM ra_material_facts AS ra
		LEFT JOIN material_fact_consumptions AS cons ON ra.doc_type='material_fact_consumption' AND ra.doc_id=cons.id
		LEFT JOIN material_fact_consumption_corrections AS cons_cor ON ra.doc_type='material_fact_consumption_correction' AND ra.doc_id=cons_cor.id
		WHERE ra.date_time BETWEEN in_date_time_from AND in_date_time_to AND NOT ra.deb AND ra.production_base_id = (SELECT prod_base.id FROM prod_base)
		GROUP BY ra.material_id
	) AS ra_kred ON ra_kred.material_id = m.id 
	WHERE concrete_part AND NOT is_cement AND NOT coalesce(dif_store,FALSE)
	ORDER BY ord
	)
	
	UNION ALL
	
	--По материалам с местами хранения
	(
	SELECT
		FALSE AS is_cement,
		m.name||', '||coalesce(st_map.store,'') AS name,
		coalesce(bal_start.quant,0) AS quant_start,
		coalesce(ra_deb.quant,0) AS quant_deb,
		coalesce(ra_kred.quant,0) AS quant_kred,
		coalesce(ra_kred.pr1_quant,0) AS pr1_quant_kred,
		coalesce(ra_deb.quant_correction,0)-coalesce(ra_kred.quant_correction,0) AS quant_correction,
		coalesce(bal_start.quant,0)+coalesce(ra_deb.quant,0)+coalesce(ra_deb.quant_correction,0)-coalesce(ra_kred.quant,0)-coalesce(ra_kred.quant_correction,0) AS quant_end
	
	FROM raw_materials AS m
	
	--остаток нач
	LEFT JOIN (
		SELECT
			t_rg.*
		FROM rg_material_facts_balance(
			in_date_time_from,
			(SELECT array_agg(prod_base.id) FROM prod_base),
			'{}',
			'{}'
		) AS t_rg
	) AS bal_start ON bal_start.material_id = m.id
	
	--Приход
	LEFT JOIN (
		SELECT
			ra.production_site_id,
			ra.material_id,
			sum(
				CASE
					WHEN ra.doc_type='material_fact_balance_correction' THEN 0
					ELSE ra.quant
				END
			) AS quant,
			sum(
				CASE
					WHEN ra.doc_type='material_fact_balance_correction' THEN ra.quant
					ELSE 0
				END
			) AS quant_correction
			
		FROM ra_material_facts AS ra
		WHERE ra.date_time BETWEEN in_date_time_from AND in_date_time_to AND ra.deb AND ra.production_base_id = (SELECT prod_base.id FROM prod_base)
		GROUP BY ra.production_site_id,ra.material_id
	) AS ra_deb ON ra_deb.material_id = m.id  AND ra_deb.production_site_id = bal_start.production_site_id
	
	--Расход
	LEFT JOIN (
		SELECT
			ra.production_site_id,
			ra.material_id,
			sum(
				CASE
					WHEN ra.doc_type='material_fact_balance_correction' THEN 0
					ELSE ra.quant
				END
			) AS quant,
			sum(
				CASE
					-- OR ra.doc_type='material_fact_consumption_correction'
					WHEN doc_type='material_fact_balance_correction' THEN ra.quant
					ELSE 0
				END
			) AS quant_correction,
			sum(
				CASE
					WHEN (ra.doc_type='material_fact_consumption' AND cons.production_site_id=5)
						OR
						(ra.doc_type='material_fact_consumption_correction' AND cons_cor.production_site_id = 5)
						THEN ra.quant
					ELSE 0
				END
			) AS pr1_quant
			
		FROM ra_material_facts AS ra
		LEFT JOIN material_fact_consumptions AS cons ON ra.doc_type='material_fact_consumption' AND ra.doc_id=cons.id
		LEFT JOIN material_fact_consumption_corrections AS cons_cor ON ra.doc_type='material_fact_consumption_correction' AND ra.doc_id=cons_cor.id
		WHERE ra.date_time BETWEEN in_date_time_from AND in_date_time_to AND NOT ra.deb AND ra.production_base_id = (SELECT prod_base.id FROM prod_base)
		GROUP BY ra.production_site_id,ra.material_id
	) AS ra_kred ON ra_kred.material_id = m.id AND ra_kred.production_site_id=bal_start.production_site_id
	
	LEFT JOIN store_map_to_production_sites AS st_map ON st_map.production_site_id = bal_start.production_site_id
	
	WHERE concrete_part AND NOT is_cement AND coalesce(dif_store,FALSE) = TRUE
	ORDER BY ord
	)
	
	;
$BODY$;

