	ORDER BY inf_on_return ASC)


	UNION ALL

	--shift && shift_added
	(SELECT *		
	FROM states_q
	WHERE  schedule_date=$1 AND (state='shift'::vehicle_states OR state='shift_added'::vehicle_states)
