-- View: shipment_for_orders_list

-- DROP VIEW shipment_for_orders_list;

CREATE OR REPLACE VIEW shipment_for_orders_list AS 
	SELECT
		sh.id,
		sh.date_time,
		sh.ship_date_time,
		sh.quant,
		vehicle_schedules_ref(vs,v,d) AS vehicle_schedules_ref,
		
		--st.state AS vs_state,
		(SELECT t.state
		FROM vehicle_schedule_states t
		WHERE t.schedule_id = vs.id
		ORDER BY t.date_time DESC
		LIMIT 1) AS vs_state,
		
		
		sh.shipped,
		o.id AS order_id,
		
		production_sites_ref(ps) AS production_sites_ref,
		
		users_ref(op_u) AS operators_ref
		
		--for client role filter
		,o.client_id
						
	FROM shipments sh
	LEFT JOIN orders o ON o.id = sh.order_id
	LEFT JOIN clients cl ON cl.id = o.client_id
	LEFT JOIN vehicle_schedules vs ON vs.id = sh.vehicle_schedule_id
	LEFT JOIN drivers d ON d.id = vs.driver_id
	LEFT JOIN vehicles v ON v.id = vs.vehicle_id
	LEFT JOIN production_sites ps ON ps.id = sh.production_site_id
	LEFT JOIN users AS op_u ON op_u.id=sh.operator_user_id
	
	/*
	LEFT JOIN (
		SELECT
			t.schedule_id,
			max(t.date_time) AS date_time
		FROM vehicle_schedule_states t
		GROUP BY t.schedule_id
	) AS s_max ON s_max.schedule_id=sh.vehicle_schedule_id
	LEFT JOIN vehicle_schedule_states st ON st.schedule_id = s_max.schedule_id AND st.date_time = s_max.date_time
	*/
	ORDER BY sh.date_time;

ALTER TABLE shipment_for_orders_list
  OWNER TO beton;



-- ******************* update 11/08/2023 15:34:36 ******************
-- FUNCTION: public.get_schedule_for_all(date, date, integer)

 DROP FUNCTION IF EXISTS public.get_schedule_for_all(date, date, integer);

CREATE OR REPLACE FUNCTION public.get_schedule_for_all(
	in_date_from date,
	in_date_to date,
	in_vehicle_id integer)
    RETURNS TABLE(
    	day date,
    	day_descr text,
    	dow integer,
    	dow_descr text,
    	week_end integer,
    	plate text,
    	owner text,
    	day_no_shift boolean,
    	productin_base text
    ) 
    LANGUAGE 'sql'
    COST 100
    VOLATILE PARALLEL UNSAFE
    ROWS 1000

AS $BODY$
	SELECT
		dt::date AS day,
		date8_descr(dt::date)::text AS day_descr,
		EXTRACT(DOW FROM dt::date)::int AS dow,
		dow_descr_short(dt::date)::text AS dow_descr,
		CASE EXTRACT(DOW FROM dt::date)
			WHEN 0 THEN 1
			WHEN 6 THEN 1
			ELSE 0
		END AS week_end,
		v.plate::text,
		--v.owner::text,
		vehicle_owner_on_date(v.vehicle_owners, in_date_from)->>'descr' AS owner,
		v.id IS NULL AS day_no_shift,
		bs.name AS productin_base

	FROM generate_series(in_date_from, in_date_to,'1 day') AS dt
	LEFT JOIN (
		SELECT DISTINCT ON (s.vehicle_id, s.schedule_date)
			s.vehicle_id,
			s.schedule_date,
			s.production_base_id
		FROM vehicle_schedules AS s
		WHERE s.schedule_date BETWEEN in_date_from AND in_date_to
		AND	CASE 
				WHEN (in_vehicle_id IS NULL) OR (in_vehicle_id=0) THEN true
				ELSE s.vehicle_id=in_vehicle_id
			END
	) AS sched ON sched.schedule_date=dt::date
	LEFT JOIN vehicles AS v ON v.id = sched.vehicle_id
	LEFT JOIN production_bases AS bs ON bs.id = sched.production_base_id
	ORDER BY
		dt,
		owner,
		plate;
$BODY$;
ALTER FUNCTION public.get_schedule_for_all(date, date, integer)
    OWNER TO beton;



