-- FUNCTION: public.recalc_consumption(in_period_id integer, in_production_site_id integer)

-- DROP FUNCTION public.recalc_consumption(in_period_id integer, in_production_site_id integer);

-- завешивает базу при большом количестве документов

CREATE OR REPLACE FUNCTION public.recalc_consumption(in_period_id integer, in_production_site_id integer)
    RETURNS void
    LANGUAGE 'sql'

    COST 100
    VOLATILE 
AS $BODY$
	/*WITH dates AS (
		SELECT
			get_shift_start(d.dt::timestamp without time zone) AS date_from,
			get_shift_end(
				get_shift_start(COALESCE(
					(SELECT d2.dt FROM raw_material_cons_rate_dates AS d2 WHERE d2.dt>d.dt ORDER BY d2.dt ASC LIMIT 1),
					now()::timestamp without time zone
				))
			) AS date_to
		FROM raw_material_cons_rate_dates AS d
		WHERE d.id = in_period_id
	)
	UPDATE shipments
		SET shipped=true
	WHERE shipped AND ship_date_time BETWEEN (SELECT date_from FROM dates) AND (SELECT date_to FROM dates)
	*/
	
	WITH dt_to AS (
		SELECT d.dt FROM raw_material_cons_rate_dates AS d WHERE d.id = in_period_id
	)
	UPDATE shipments
		SET shipped = true
	WHERE shipped
		AND ship_date_time BETWEEN
			coalesce(
				(SELECT d.dt
				FROM raw_material_cons_rate_dates AS d
				WHERE d.dt > (SELECT dt FROM dt_to)
				ORDER BY d.dt DESC
				LIMIT 1),
				now()::timestamp without time zone
			)
			AND (SELECT dt FROM dt_to)
		AND production_site_id = in_production_site_id
	;
	
$BODY$;

