		,sum(sub.material_req_cost) AS material_req_cost
		,CASE WHEN sum(sub.concrete_quant)=0 THEN 0 ELSE round( (sum(sub.material_req_cost) / sum(sub.concrete_quant))::numeric(19,4) ,2) END AS material_req_cost_per_m3
		
	FROM
	(
	SELECT
