﻿-- Function: quality_passports_object_or_last(in_quality_passport int)

-- DROP FUNCTION quality_passports_object_or_last(in_quality_passport int);

CREATE OR REPLACE FUNCTION quality_passports_object_or_last(in_quality_passport int)
  RETURNS quality_passports AS
$$
BEGIN
	IF coalesce(in_quality_passport, 0) > 0 THEN
		SELECT
			quality_passports.*
		FROM quality_passports
		WHERE id = in_quality_passport;
	ELSE
		SELECT
			quality_passports.*
		FROM quality_passports
		ORDER BY vidan DESC
		LIMIT 1;
	END IF;
END;
$$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION quality_passports_object_or_last(in_quality_passport int) OWNER TO beton;


