			pas.kf_prochnosti AS kf_prochnosti,
			pas.prochnost::text AS prochnost,
			pas.naim_dobavki AS naim_dobavki,
			pas.aeff AS aeff,
			pas.krupnost::text AS krupnost,
			to_char(o.date_time, 'dd/mm/yyyy') AS vidan
			
		FROM shipments AS sh
		LEFT JOIN orders AS o ON o.id = sh.order_id
		LEFT JOIN clients AS cl ON cl.id = o.client_id
		LEFT JOIN concrete_types AS ct ON ct.id = o.concrete_type_id
		LEFT JOIN quality_passports AS pas ON pas.shipment_id = in_shipment_id
		WHERE sh.order_id = (SELECT id FROM sh_orders)
		GROUP BY
			cl.name_full, cl.name,
			o.date_time,
			o.number,
			ct.official_name,
			pas.uklad,
			pas.f_val,pas.w_val,
			pas.vid_smesi_gost,
			pas.sohran_udobouklad,
			pas.kf_prochnosti,
			pas.prochnost,
			pas.naim_dobavki,
			pas.aeff,
			pas.krupnost			
		;
	ELSE
		-- one shipment
		RETURN QUERY
		WITH
		podbor AS (
			SELECT
				rt_h.id
			FROM raw_material_cons_rate_dates AS rt_h
			WHERE rt_h.production_site_id = (SELECT sh.production_site_id FROM shipments AS sh WHERE sh.id = in_shipment_id)
			ORDER BY rt_h.dt DESC
			LIMIT 1
		),
		podbor_mat_num AS (
			SELECT
				sub.concrete_type_id,
				ROW_NUMBER() OVER() AS r_num
			FROM (
				SELECT DISTINCT ON (ctp.name)
					t.concrete_type_id,
					t.concrete_types_ref
				FROM raw_material_cons_rates_list AS t
				LEFT JOIN concrete_types AS ctp ON ctp.id=t.concrete_type_id
				WHERE rate_date_id = (SELECT podbor.id FROM podbor)
				ORDER BY ctp.name
			) AS sub		
		)
		SELECT
			--o.number
			'Документ о качестве бетонной смеси заданного качества партии № '||(pas.id)::text AS nomer,
			coalesce(cl.name_full, cl.name) AS client,
			FORMAT('БСТ F%sW%s %s', pas.f_val::text, pas.w_val::text, pas.vid_smesi_gost::text) AS smes,
			pas.uklad AS uklad,
			
			--ID подбора/порядковый номер материала в подбре
			(SELECT podbor.id::text FROM podbor) || '/' ||
				(SELECT podbor_mat_num.r_num::text
				FROM podbor_mat_num
				WHERE podbor_mat_num.concrete_type_id = o.concrete_type_id
				)
			AS smes_num,
			
			REPLACE(sh.quant::text, '.', ',') || ' м3' AS obiem,
			to_char(sh.ship_date_time, 'dd/mm/yy HH24:MI') vremia_otpravki,
			ct.official_name::text AS klass_prochnosti,
			FORMAT('F%sW%s', pas.f_val::text, pas.w_val::text) AS drugie_pokazateli_kach,
			pas.sohran_udobouklad AS sohran_udobouklad,
			pas.kf_prochnosti AS kf_prochnosti,
			pas.prochnost::text AS prochnost,
			pas.naim_dobavki AS naim_dobavki,
			pas.aeff AS aeff,
			pas.krupnost::text AS krupnost,
			to_char(sh.date_time, 'dd/mm/yyyy') AS vidan
			
		FROM shipments AS sh
		LEFT JOIN orders AS o ON o.id = sh.order_id
		LEFT JOIN clients AS cl ON cl.id = o.client_id
		LEFT JOIN concrete_types AS ct ON ct.id = o.concrete_type_id
		LEFT JOIN quality_passports AS pas ON pas.shipment_id = sh.id
		WHERE sh.id = in_shipment_id;
	END IF;		
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100
  ROWS 1000;
ALTER FUNCTION passport_print(in_shipment_id int, in_all bool) OWNER TO beton;


