﻿-- Function: passport_print(in_shipment_id int, in_all bool)

-- DROP FUNCTION passport_print(in_shipment_id int, in_all bool);

CREATE OR REPLACE FUNCTION passport_print(in_shipment_id int, in_all bool)
  RETURNS table(
  	nomer text,
  	client text,
  	smes text,
  	uklad text,
  	smes_num text,
  	obiem text,
  	vremia_otpravki text,
	klass_prochnosti text,
	drugie_pokazateli_kach text,
	sohran_udobouklad text,
	kf_prochnosti text,
	prochnost text,
	naim_dobavki text,
	aeff text,
	krupnost text,
	vidan text,
	reg_nomer_dekl text
  ) AS
$BODY$
BEGIN
	IF in_all THEN
		-- all shipments
		RETURN QUERY
		WITH
		sh_orders AS (SELECT t.order_id AS id FROM shipments AS t WHERE t.id = in_shipment_id)
		
		SELECT
			--o.number order_num(o.*)
			'Документ о качестве бетонной смеси заданного качества партии № '||
				(SELECT 
				CASE WHEN EXTRACT(DAY FROM o.date_time)<10 THEN
					'0' || EXTRACT(DAY FROM o.date_time)::varchar || '-' || trim(to_char(o.number,'000'))
				ELSE
					EXTRACT(DAY FROM o.date_time)::varchar || '-' || trim(to_char(o.number,'000'))
				END)
			AS nomer,
			coalesce(cl.name_full, cl.name) AS client,
			FORMAT('БСТ %s F%sW%s %s', ct.official_name::text, pas.f_val::text, pas.w_val::text, pas.vid_smesi_gost::text) AS smes,
			pas.uklad AS uklad,
			
			--ID подбора/порядковый номер материала в подбре
			pas.smes_num AS smes_num,
			
			REPLACE(sum(sh.quant)::text, '.', ',') || ' м3' AS obiem,
			to_char(o.date_time, 'dd/mm/yy') || (
				SELECT
					to_char(min(t.ship_date_time), 'HH24:MI')|| ' - ' ||to_char(max(t.ship_date_time), 'HH24:MI')
				FROM shipments AS t
				WHERE t.order_id = (SELECT id FROM sh_orders)
			) AS vremia_otpravki,
			ct.official_name::text AS klass_prochnosti,
			FORMAT('F%sW%s', pas.f_val::text, pas.w_val::text) AS drugie_pokazateli_kach,
			pas.sohran_udobouklad AS sohran_udobouklad,
			pas.kf_prochnosti AS kf_prochnosti,
			pas.prochnost::text AS prochnost,
			pas.naim_dobavki AS naim_dobavki,
			pas.aeff AS aeff,
			pas.krupnost::text AS krupnost,
			to_char(o.date_time, 'dd/mm/yyyy') AS vidan,
			pas.reg_nomer_dekl::text AS reg_nomer_dekl
			
		FROM shipments AS sh
		LEFT JOIN orders AS o ON o.id = sh.order_id
		LEFT JOIN clients AS cl ON cl.id = o.client_id
		LEFT JOIN concrete_types AS ct ON ct.id = o.concrete_type_id
		LEFT JOIN quality_passports AS pas ON pas.shipment_id = in_shipment_id
		WHERE sh.order_id = (SELECT id FROM sh_orders)
		GROUP BY
			cl.name_full, cl.name,
			o.date_time,
			o.number,
			ct.official_name,
			pas.uklad,
			pas.f_val,pas.w_val,
			pas.vid_smesi_gost,
			pas.sohran_udobouklad,
			pas.kf_prochnosti,
			pas.prochnost,
			pas.naim_dobavki,
			pas.aeff,
			pas.krupnost,
			pas.reg_nomer_dekl,
			pas.id			
		;
	ELSE
		-- one shipment
		RETURN QUERY
		WITH
		ship_num AS (
			SELECT
				ROW_NUMBER() OVER() AS num,
				sh.id
			FROM shipments AS sh
			WHERE sh.order_id = (SELECT sh_t.order_id FROM shipments AS sh_t WHERE sh_t.id = in_shipment_id)
			ORDER BY sh.ship_date_time		
		)
		SELECT
			--o.number/shipment порядковый номер отрузки
			'Документ о качестве бетонной смеси заданного качества партии № '||
				(SELECT 
				CASE WHEN EXTRACT(DAY FROM o.date_time)<10 THEN
					'0' || EXTRACT(DAY FROM o.date_time)::varchar || '-' || trim(to_char(o.number,'000'))
				ELSE
					EXTRACT(DAY FROM o.date_time)::varchar || '-' || trim(to_char(o.number,'000'))
				END) ||'/'|| (SELECT ship_num.num::text FROM ship_num WHERE ship_num.id = in_shipment_id)			
			AS nomer,
			
			coalesce(cl.name_full, cl.name) AS client,
			FORMAT('БСТ %s F%sW%s %s', ct.official_name::text, pas.f_val::text, pas.w_val::text, pas.vid_smesi_gost::text) AS smes,
			pas.uklad AS uklad,
			
			--ID подбора/порядковый номер материала в подбре
			pas.smes_num AS smes_num,
			
			REPLACE(sh.quant::text, '.', ',') || ' м3' AS obiem,
			to_char(sh.ship_date_time, 'dd/mm/yy HH24:MI') vremia_otpravki,
			ct.official_name::text AS klass_prochnosti,
			FORMAT('F%sW%s', pas.f_val::text, pas.w_val::text) AS drugie_pokazateli_kach,
			pas.sohran_udobouklad AS sohran_udobouklad,
			pas.kf_prochnosti AS kf_prochnosti,
			pas.prochnost::text AS prochnost,
			pas.naim_dobavki AS naim_dobavki,
			pas.aeff AS aeff,
			pas.krupnost::text AS krupnost,
			to_char(sh.date_time, 'dd/mm/yyyy') AS vidan,
			pas.reg_nomer_dekl::text AS reg_nomer_dekl
			
		FROM shipments AS sh
		LEFT JOIN orders AS o ON o.id = sh.order_id
		LEFT JOIN clients AS cl ON cl.id = o.client_id
		LEFT JOIN concrete_types AS ct ON ct.id = o.concrete_type_id
		LEFT JOIN quality_passports AS pas ON pas.shipment_id = sh.id
		WHERE sh.id = in_shipment_id;
	END IF;		
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100
  ROWS 1000;
ALTER FUNCTION passport_print(in_shipment_id int, in_all bool) OWNER TO beton;


-- ******************* update 15/01/2024 11:23:12 ******************
-- VIEW: quality_passports_list

--DROP VIEW quality_passports_list;

CREATE OR REPLACE VIEW quality_passports_list AS
	SELECT
		t.id 
		,t.f_val
		,t.w_val
		,t.vid_smesi_gost
		,t.uklad
		,t.sohran_udobouklad
		,t.kf_prochnosti
		,t.prochnost
		,t.naim_dobavki
		,t.aeff
		,t.krupnost
		,t.vidan
		,t.smes_num
		,orders_ref(o) AS orders_ref
		,concrete_types_ref(ctp) AS concrete_types_ref
		,clients_ref(cl) AS clients_ref
		,(
			SELECT
				json_agg(shipments_ref(sh))
			FROM shipments AS sh
			WHERE sh.order_id = t.order_id
		) AS shipments_list
		
	FROM quality_passports AS t
	LEFT JOIN orders AS o ON o.id = t.order_id
	LEFT JOIN concrete_types AS ctp ON ctp.id = o.concrete_type_id
	LEFT JOIN clients AS cl ON cl.id = o.client_id
	ORDER BY t.vidan DESC
	;
	
ALTER VIEW quality_passports_list OWNER TO beton;


-- ******************* update 15/01/2024 11:27:42 ******************
﻿-- Function: quality_passports_object_or_last(in_shipment_id int)

-- DROP FUNCTION quality_passports_object_or_last(in_shipment_id int);

CREATE OR REPLACE FUNCTION quality_passports_object_or_last(in_shipment_id int)
  RETURNS quality_passports AS
$$
DECLARE
	v_quality_passport_id int;
BEGIN
	SELECT id INTO v_quality_passport_id FROM quality_passports WHERE shipment_id = in_shipment_id;
	
	IF v_quality_passport_id IS NOT NULL THEN
		-- passport exists
		RETURN
			(SELECT
				ROW(quality_passports.*)
			FROM quality_passports
			WHERE id = v_quality_passport_id
		);	
	ELSE
		--no passport - defaults
		RETURN
			(
			WITH
			-- f_val, w_val - from order
			-- prochnost - from concrete type
			ord_d AS (SELECT
					o.date_time::date AS vidan,
					o.f_val,
					o.w_val,
					ctp.prochnost,
					o.concrete_type_id
				FROM orders AS o
				LEFT JOIN concrete_types AS ctp ON ctp.id = o.concrete_type_id
				WHERE o.id = (SELECT sh.order_id FROM shipments AS sh WHERE sh.id = in_shipment_id)
			),
			--last passport with same concrete type
			last_qp AS (SELECT
					qp.*
				FROM quality_passports AS qp				
				LEFT JOIN shipments AS sh ON sh.id = qp.shipment_id
				LEFT JOIN orders AS o ON o.id = sh.order_id
				WHERE o.concrete_type_id = (SELECT concrete_type_id FROM ord_d)
				ORDER BY qp.vidan DESC
				LIMIT 1
			)	
			SELECT
				ROW(
					0,
					coalesce(coalesce( (SELECT f_val FROM ord_d), (SELECT f_val FROM last_qp) ), 200),
					coalesce(coalesce( (SELECT w_val FROM ord_d), (SELECT w_val FROM last_qp) ), 8),
					coalesce((SELECT vid_smesi_gost FROM last_qp), 'ГОСТ 7473-2010'),					
					coalesce((SELECT uklad FROM last_qp), 'П4 ( ОК 16-20 см.)'),
					coalesce((SELECT sohran_udobouklad FROM last_qp), '2 ч 00 мин'),
					coalesce((SELECT kf_prochnosti FROM last_qp), '11,5 (по схеме А)'),
					coalesce(coalesce((SELECT prochnost FROM ord_d), (SELECT prochnost FROM last_qp)), 30),
					coalesce((SELECT naim_dobavki FROM last_qp), 'Противоморозная Криопласт Экстра, 1%'),
					coalesce((SELECT aeff FROM last_qp), '1 Класс до 370 Бк/кг, Цемент - 86 Бк/кг, Песок-16,2 Бк/кг, Щебень - 28,8Бк/кг'),
					coalesce((SELECT krupnost FROM last_qp), 20),
					(SELECT vidan FROM ord_d),
					in_shipment_id,
					coalesce(quality_passports_smes_num((SELECT concrete_type_id FROM ord_d), in_shipment_id), ''::text),
					0,
					0,
					coalesce((SELECT last_qp.reg_nomer_dekl::text FROM last_qp), ''::text)
				)
			);			
	END IF;
END
$$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION quality_passports_object_or_last(in_shipment_id int) OWNER TO beton;


